const QUESTIONS_SECX_C5 = [
  { id:70901, domain:1, level:3, question:"A retail enterprise is migrating to zero trust. Which design best embodies never-trust-always-verify for east-west traffic?", options:["Enforcing per-session microsegmentation validated by identity and device posture at each network hop","Placing all servers behind one perimeter firewall with stateful packet inspection enabled now","Granting flat VLAN access once a host authenticates to the corporate VPN concentrator first","Trusting internal subnets implicitly while inspecting only inbound traffic from the public internet in practice as well as in theory"], correct:0, explanation:"Microsegmentation with continuous identity and posture checks is core to zero trust; perimeter-only firewalls and flat VLANs grant implicit internal trust that zero trust rejects." },
  { id:70902, domain:1, level:2, question:"An architect must isolate a legacy SCADA segment that cannot be patched while preserving telemetry. Which approach fits best?", options:["Place the SCADA hosts on the same VLAN as IT workstations to make monitoring much simpler","Deploy a unidirectional data diode allowing telemetry outbound while physically blocking inbound connections","Expose the historian directly to the internet behind only a single NAT translation rule today","Remove all existing network segmentation so engineers can reach the devices from anywhere quickly according to the proposed plan"], correct:1, explanation:"A data diode physically enforces one-way flow protecting unpatchable OT; flat VLANs and direct exposure increase rather than reduce the attack surface." },
  { id:70903, domain:1, level:3, question:"A SaaS provider needs tenant isolation in a shared Kubernetes cluster. Which control most directly blocks cross-tenant service reachability?", options:["Increasing the CPU and memory resource quotas that are assigned to each tenant namespace daily","Enabling verbose audit logging on the cluster API server for every tenant action performed","Network policies enforcing namespace-scoped ingress and egress rules between separate tenant workloads","Rotating the container image registry credentials on a fixed weekly automated maintenance schedule whenever the situation arises"], correct:2, explanation:"Kubernetes NetworkPolicies restrict pod-to-pod traffic across namespaces; quotas, logging, and credential rotation do not block lateral network reachability." },
  { id:70904, domain:1, level:2, question:"In a secure cloud landing zone, what is the primary benefit of a hub-and-spoke topology with a centralized inspection VPC?", options:["Eliminating the need for any identity-based access controls on the deployed cloud resources entirely","Removing the requirement to encrypt data at rest across all of the storage buckets in use","Allowing every spoke to peer directly with every other spoke purely to reduce network latency","Consolidated egress inspection and shared services without fully meshing every workload VPC together"], correct:3, explanation:"A hub centralizes inspection and shared services; full spoke-to-spoke meshing defeats the model, and the topology does not replace IAM or encryption." },
  { id:70905, domain:1, level:3, question:"An enterprise wants consistent security policy across multi-cloud workloads. Which component provides vendor-neutral enforcement?", options:["A cloud-agnostic policy-as-code engine integrated into the CI/CD pipeline and runtime admission paths","A single cloud provider's native firewall applied only within that one provider's own regions","Manual spreadsheet tracking of each cloud account's security group configurations done by hand","Per-team ad hoc scripts that each implement their own separate interpretation of the policy rules during day-to-day operations"], correct:0, explanation:"Policy-as-code in pipelines and admission controllers gives uniform vendor-neutral guardrails; native single-cloud tools and ad hoc scripts cannot span providers consistently." },
  { id:70906, domain:1, level:2, question:"A company adopts SASE. Which statement best describes how SASE changes traditional network security architecture?", options:["It centralizes all of the organization's traffic through a single on-premises data center chokepoint in the scenario being described","It converges networking and security functions into a cloud-delivered service positioned close to users","It eliminates the need to authenticate users at all before granting them access to applications","It replaces encryption with simple reputation scoring for every outbound web request that is made"], correct:1, explanation:"SASE delivers converged network and security as a cloud edge near users; it does not backhaul to one DC nor remove authentication or encryption." },
  { id:70907, domain:1, level:1, question:"Which architectural concept describes layering independent controls so one component's failure does not compromise the whole system?", options:["Single sign-on applied uniformly across every enterprise application that users need to reach","Flat network design adopted primarily for the sake of simplified ongoing administration","Defense in depth using multiple layered and independent security controls throughout the environment","Implicit trust granted to all traffic that originates from inside the corporate network boundary over the lifetime of the system"], correct:2, explanation:"Defense in depth layers independent controls so one failure is contained; SSO, flat networks, and implicit trust do not provide layered containment." },
  { id:70908, domain:1, level:3, question:"A bank designs a high-assurance enclave for cryptographic key operations. Which HSM placement best limits exposure?", options:["Directly reachable from any application server over the shared general-purpose corporate LAN segment","Hosted on an individual developer laptop in order to speed up the integration testing cycles","Published to the public internet so external partners can call signing operations on it directly","Behind a dedicated management network with API access mediated by an attested key broker service"], correct:3, explanation:"Mediating HSM access through an attested broker on an isolated network minimizes exposure; LAN, laptop, or internet access widen risk drastically." },
  { id:70909, domain:1, level:2, question:"An architect evaluates an API gateway for microservices. Which capability most improves north-south traffic security?", options:["Centralized authentication, rate limiting, and schema validation enforced before requests reach services","Caching static responses primarily to reduce the backend compute costs during heavy traffic spikes under typical operating conditions","Translating between SOAP and REST so that older legacy clients are still able to connect today","Load balancing requests evenly across service replicas spread over multiple availability zones"], correct:0, explanation:"Centralized authN, rate limiting, and schema validation protect services; caching, protocol translation, and load balancing are functional but not security controls." },
  { id:70910, domain:1, level:3, question:"A hybrid enterprise wants on-prem identities to govern cloud access without syncing password hashes. Which design fits?", options:["Exporting all of the Active Directory password hashes nightly into the cloud directory service","Federated authentication via SAML or OIDC with the on-premises identity provider as authoritative source","Creating duplicate standalone accounts in each cloud platform with their own separate credentials across the affected systems","Sharing a single service account credential among all employees for every cloud sign-in attempt"], correct:1, explanation:"Federation lets the on-prem IdP assert identity without hash sync; hash export, duplicate accounts, and shared credentials are insecure or defeat the requirement." },
  { id:70911, domain:1, level:3, question:"A design team must prevent server-side request forgery in a metadata-rich cloud environment. Which architectural control is most effective?", options:["Relying on application developers to remember to validate every user-supplied URL each time","Allowing outbound traffic from workloads to any internal address to simplify service discovery","Enforcing IMDSv2 with session tokens and an egress allowlist that blocks access to the metadata endpoint","Trusting the cloud provider default configuration without any additional hardening applied at all for the foreseeable future"], correct:2, explanation:"IMDSv2 plus egress controls structurally block SSRF to metadata; developer diligence and open egress are unreliable, and defaults are insufficient." },
  { id:70912, domain:1, level:2, question:"Which architectural pattern best limits blast radius if a single microservice is compromised?", options:["A shared admin credential reused by all services to simplify inter-service authentication greatly","A single flat trust zone where any service may call any other service without restriction at all","Disabling logging on internal services to reduce the overhead of east-west traffic inspection","Least-privilege service identities with mutual TLS and per-service network segmentation enforced"], correct:3, explanation:"Per-service identity, mTLS, and segmentation contain a compromise; shared credentials, flat trust, and disabled logging amplify and hide lateral movement." },
  { id:70913, domain:1, level:3, question:"An organization adopts an identity-aware proxy for application access. What threat does this most directly mitigate?", options:["Unauthorized access from compromised networks by requiring per-request identity and context evaluation","Cryptographic weaknesses in the TLS cipher suites negotiated by external client browsers in practice as well as in theory","Physical theft of the laptops that employees carry between office and home locations","Supply-chain tampering within third-party container images pulled from public registries"], correct:0, explanation:"An identity-aware proxy evaluates identity and context per request, mitigating network-trust abuse; it does not address cipher strength, physical theft, or image tampering." },
  { id:70914, domain:1, level:2, question:"A secure architecture requires that compromise of the CI/CD system cannot directly grant production access. Which control achieves this?", options:["A persistent production admin key stored as a plaintext variable inside the pipeline configuration","Short-lived workload identities with deployment approvals gating promotion into the production environment","Granting the build agents standing administrative rights across all production cloud accounts always according to the proposed plan","Allowing any developer to trigger production deploys without any review or approval step at all"], correct:1, explanation:"Ephemeral workload identities plus approval gates break the direct path from CI/CD to prod; stored admin keys and standing rights make compromise catastrophic." },
  { id:70915, domain:1, level:1, question:"Which deployment model keeps sensitive workloads on-premises while bursting less-sensitive workloads to public cloud?", options:["A purely public multi-tenant cloud model where every workload runs on shared provider hardware whenever the situation arises","A fully air-gapped network with no external connectivity to any cloud provider whatsoever","A hybrid cloud architecture spanning on-premises and public cloud resources for differing sensitivity","A single-tenant private data center that never sends any workload outside its own walls at all"], correct:2, explanation:"Hybrid cloud keeps sensitive workloads local while bursting others to public cloud; pure public, air-gapped, and single private models do not match that requirement." },
  { id:70916, domain:1, level:3, question:"An architect must protect a public-facing web app from automated abuse without harming legitimate users. Which layered control set is strongest?", options:["A single static rate limit applied uniformly to all source addresses regardless of behavior seen","Geographic blocking of entire countries chosen arbitrarily without analyzing actual request patterns as the architecture currently stands","Relying solely on the application code to reject malformed input after it reaches the backend","A WAF with managed rules, bot management, and adaptive rate limiting tied to risk scoring at the edge"], correct:3, explanation:"WAF plus bot management and adaptive rate limiting handle abuse while preserving good traffic; static limits, geo-blocking, and code-only defense are blunt or late." },
  { id:70917, domain:1, level:2, question:"A zero-trust rollout requires continuous evaluation of device trust. Which signal is most appropriate to feed the policy engine?", options:["Real-time device posture such as patch level, disk encryption state, and EDR health attestation","The static IP address range that the device happened to use during initial enrollment only during day-to-day operations","The brand and color of the laptop chassis recorded once at the time of purchase by IT","The number of years the employee has worked at the company according to HR records today"], correct:0, explanation:"Real-time posture (patching, encryption, EDR health) drives adaptive trust decisions; static IPs, hardware cosmetics, and tenure are not security posture signals." },
  { id:70918, domain:1, level:3, question:"A multinational must keep certain data within national borders. Which architectural approach satisfies data residency requirements?", options:["Replicating all data globally to every region so that latency is minimized for everyone equally","Deploying regionally scoped infrastructure with data localization controls enforced per jurisdiction","Storing all data in a single low-cost region regardless of where the data subjects reside legally in the scenario being described","Encrypting the data once and assuming that encryption alone satisfies every residency obligation"], correct:1, explanation:"Region-scoped infrastructure with localization controls meets residency mandates; global replication, single-region storage, and encryption alone do not constrain location." },
  { id:70919, domain:1, level:2, question:"Which control best enforces separation between development, staging, and production in a cloud organization?", options:["A shared single account where environments are separated only by naming conventions on resources","One IAM role with full privileges across all environments to make administration far simpler","Distinct accounts or subscriptions per environment with isolated IAM boundaries and network controls","Manual reminders to engineers not to touch production resources while working on development work over the lifetime of the system"], correct:2, explanation:"Separate accounts with isolated IAM and networking provide strong environment separation; naming-only, shared roles, and reminders do not enforce boundaries." },
  { id:70920, domain:1, level:3, question:"An enterprise wants resilient DNS that resists hijacking and cache poisoning. Which combination best meets the goal?", options:["Pointing all clients to a single public resolver chosen for its very fast response times only","Disabling DNS caching everywhere to ensure that every lookup always reaches the authoritative server","Using only internal hosts files distributed to clients in place of any DNS resolution at all","DNSSEC validation combined with registrar lock and monitoring of authoritative record changes"], correct:3, explanation:"DNSSEC, registrar lock, and change monitoring counter hijacking and poisoning; a single fast resolver, no caching, or hosts files do not provide cryptographic integrity." },
  { id:70921, domain:1, level:2, question:"A serverless architecture needs to limit the impact of an over-privileged function. Which practice is most effective?", options:["Granting each function a narrowly scoped execution role following least privilege for its specific task","Attaching a broad administrator policy to every function to avoid permission errors during runtime under typical operating conditions","Sharing one execution role across all functions in the account to simplify ongoing maintenance","Disabling function logging so that potential attackers cannot learn which permissions are in use"], correct:0, explanation:"Per-function least-privilege roles limit blast radius; broad admin policies, shared roles, and disabled logging increase risk and reduce visibility." },
  { id:70922, domain:1, level:3, question:"An architect integrates an on-prem data center with cloud over a dedicated circuit. Which control protects confidentiality on that link?", options:["Assuming the dedicated circuit is inherently private and therefore needs no encryption at all","Encrypting traffic with IPsec or MACsec over the private circuit rather than trusting the link alone","Sending the data in plaintext because the carrier promised that the circuit is fully isolated","Relying only on application-layer compression to make the captured traffic harder to interpret across the affected systems"], correct:1, explanation:"Encrypting with IPsec/MACsec protects confidentiality even on private links; assuming inherent privacy, plaintext, or compression do not provide confidentiality." },
  { id:70923, domain:1, level:2, question:"Which design principle dictates that a system should grant only the minimum access necessary to perform a function?", options:["Complete mediation requiring that every single access be checked against an external clock signal for the foreseeable future","Security through obscurity achieved by hiding the existence of sensitive systems from staff","Least privilege applied consistently to users, services, and automated workloads across the system","Open design publishing all secrets so that defenders and attackers have identical knowledge"], correct:2, explanation:"Least privilege grants only minimum necessary access; complete mediation, obscurity, and open design are different concepts and the latter two are weak strategies." },
  { id:70924, domain:1, level:3, question:"A company wants to detect lateral movement architecturally rather than only with endpoint tools. Which design supports this best?", options:["Removing all internal firewalls so that traffic flows freely and is therefore easier to observe","Trusting that perimeter defenses will stop every attacker before they ever reach internal systems","Logging only successful authentications while discarding all failed and anomalous attempts entirely throughout the whole environment","Deploying internal segmentation with deception assets and flow logging between trust zones for visibility"], correct:3, explanation:"Segmentation, deception, and inter-zone flow logging expose lateral movement; removing firewalls, perimeter-only trust, and discarding anomalies hide it." },
  { id:70925, domain:1, level:2, question:"Which architectural choice best supports secure secrets distribution to ephemeral containers?", options:["Injecting secrets at runtime from a managed vault using short-lived tokens tied to workload identity","Baking long-lived secrets into the container image so they are always available on startup","Storing secrets in environment variables committed to the source repository for convenience in practice as well as in theory","Emailing secrets to the deployment team to paste manually whenever a container is launched"], correct:0, explanation:"Runtime injection from a vault with short-lived, identity-bound tokens is secure; baked-in, repo-committed, or emailed secrets leak easily and persist." },
  { id:70926, domain:1, level:3, question:"An enterprise adopts microsegmentation but worries about policy sprawl. Which approach keeps policy manageable and consistent?", options:["Writing one firewall rule per individual IP pair and maintaining them all manually over time","Defining segmentation policies by workload identity and labels rather than by static IP addresses","Allowing any-to-any within each segment so that fewer rules are needed across the environment according to the proposed plan","Disabling segmentation periodically during deployments to avoid having to update the policies"], correct:1, explanation:"Identity- and label-based policy scales and survives IP changes; per-IP rules, any-to-any, and disabling segmentation cause sprawl or weaken isolation." },
  { id:70927, domain:1, level:2, question:"Which control most directly enforces that only signed and approved container images run in production?", options:["A nightly report listing which images ran, reviewed by a person the following business morning whenever the situation arises","A naming convention requiring approved images to start with the word prod in the registry","An admission controller that verifies image signatures and provenance before scheduling workloads","Trusting developers to only ever push images that they personally believe are safe to deploy"], correct:2, explanation:"Admission control verifying signatures and provenance blocks unapproved images at deploy time; reports, naming, and trust do not prevent execution." },
  { id:70928, domain:1, level:3, question:"A financial firm needs an architecture that survives loss of an entire cloud region. Which design meets the RTO best?", options:["A single-region deployment with backups copied to the same region's secondary storage tier only as the architecture currently stands","Manual restoration from offline tapes shipped to a new region after a regional outage occurs","Relying on the cloud provider to silently move the workload elsewhere without any planning","Active-active deployment across regions with automated failover and continuously replicated state"], correct:3, explanation:"Multi-region active-active with automated failover minimizes RTO; same-region backups, manual tape restores, and assuming provider rescue do not survive regional loss." },
  { id:70929, domain:1, level:2, question:"Which approach best secures machine-to-machine communication in an internal service mesh?", options:["Mutual TLS between services with a mesh control plane managing certificate issuance and rotation","A shared static API key embedded in each service and never rotated for the life of the system during day-to-day operations","Plaintext HTTP inside the mesh because all of the traffic stays within the cluster boundary","Allowing services to skip authentication entirely as long as they are in the same namespace"], correct:0, explanation:"mTLS with automated cert lifecycle secures service-to-service traffic; static keys, plaintext, and skipped auth leave the mesh exposed." },
  { id:70930, domain:1, level:3, question:"An architect must design for secure remote administration of cloud infrastructure. Which model minimizes standing exposure?", options:["Permanent SSH keys on a jump host that every administrator shares and reuses indefinitely","Just-in-time privileged access through a broker with session recording and time-bound elevation","Direct RDP exposure of management hosts to the internet protected only by a password login in the scenario being described","A single always-on VPN granting full administrative network reach to anyone who connects"], correct:1, explanation:"JIT brokered access with recording and time-bound elevation minimizes standing privilege; shared permanent keys, exposed RDP, and broad VPN expand attack surface." },
  { id:70931, domain:1, level:2, question:"Which design best ensures that logs cannot be tampered with by an attacker who compromises a host?", options:["Keeping all logs only on the local disk of the host that generated them for easy access","Allowing administrators to edit historical log files to correct any formatting mistakes found over the lifetime of the system","Streaming logs in near real time to a write-once external store outside the host's control plane","Rotating logs hourly and overwriting the oldest entries to conserve local storage capacity"], correct:2, explanation:"Shipping logs to a write-once external store preserves integrity after host compromise; local-only, editable, or overwritten logs can be altered or destroyed." },
  { id:70932, domain:1, level:3, question:"A company integrates IoT devices into its network. Which architecture best contains the risk these constrained devices introduce?", options:["Placing IoT devices on the main user VLAN so that staff can manage them from their desks","Allowing IoT devices unrestricted outbound internet access to reach their vendor cloud services in most real deployments","Disabling network monitoring on IoT traffic because the devices generate too much noise daily","A dedicated IoT segment with strict egress policies, a gateway broker, and behavioral monitoring"], correct:3, explanation:"A segmented IoT zone with egress control, a broker, and monitoring contains risk; shared VLANs, open egress, and no monitoring let weak devices endanger the network." },
  { id:70933, domain:1, level:2, question:"Which control best mitigates the risk of a compromised third-party SaaS integration accessing excessive data?", options:["Scoping OAuth grants to least privilege and reviewing third-party app permissions on a regular cadence","Granting every integration full read and write access to all data to avoid permission errors later","Trusting the SaaS vendor's security posture and therefore skipping any permission review entirely","Sharing a privileged user's personal credentials with the integration instead of using OAuth scopes under typical operating conditions"], correct:0, explanation:"Least-privilege OAuth scopes plus periodic review limit third-party exposure; full grants, blind trust, and shared credentials over-expose data." },
  { id:70934, domain:1, level:3, question:"An enterprise wants to enforce encryption-in-transit for all internal services without rewriting applications. Which approach is most practical?", options:["Requiring every development team to manually add TLS code to each of their own services","A service mesh sidecar that transparently establishes mutual TLS between application workloads","Encrypting only the perimeter and leaving all internal service traffic as plaintext for speed across the affected systems","Disabling encryption internally and relying on physical security of the data center instead"], correct:1, explanation:"A mesh sidecar adds transparent mTLS without app changes; manual per-app TLS is slow and inconsistent, and perimeter-only or physical-only approaches leave internal traffic exposed." },
  { id:70935, domain:1, level:2, question:"Which architectural element provides centralized, consistent authorization decisions across many applications?", options:["A copy of the access rules hardcoded separately into every individual application's source code for the foreseeable future","A shared spreadsheet of who may access what, consulted manually by administrators when asked","An external policy decision point evaluating fine-grained authorization requests from each application","Per-application admin accounts whose privileges are never reviewed once they are first granted"], correct:2, explanation:"An external PDP centralizes consistent authorization; hardcoded rules, spreadsheets, and unreviewed admin accounts are inconsistent and error-prone." },
  { id:70936, domain:1, level:3, question:"A design must prevent exfiltration of data from a cloud environment via DNS tunneling. Which control is most targeted?", options:["Allowing all DNS traffic outbound because DNS is required for normal operation of the systems","Blocking only TCP port 53 while leaving UDP port 53 completely unrestricted to all destinations throughout the whole environment","Relying on endpoint antivirus signatures to detect the tunneling tool after it is installed","Inspecting and rate-limiting DNS with anomaly detection on query length, entropy, and volume patterns"], correct:3, explanation:"DNS inspection with anomaly detection on length, entropy, and volume targets tunneling; open DNS, partial port blocking, and AV signatures miss the exfiltration channel." },
  { id:70937, domain:1, level:2, question:"Which architectural decision best supports secure decommissioning of cloud resources containing sensitive data?", options:["Automated workflows that revoke access, crypto-shred keys, and confirm storage deletion with evidence","Simply detaching the resource from the console and assuming the provider will clean it up later","Leaving the resource running but renaming it so that nobody is likely to use it going forward","Deleting only the console bookmark pointing to the resource while the data itself remains intact in practice as well as in theory"], correct:0, explanation:"Automated revocation, crypto-shredding, and verified deletion ensure secure decommissioning; detaching, renaming, or removing bookmarks leave data recoverable." },
  { id:70938, domain:1, level:3, question:"An organization needs to allow partner access to specific internal APIs without exposing its whole network. Which architecture fits best?", options:["A site-to-site VPN granting each partner full routed access to the internal corporate network according to the proposed plan","A brokered API exposure through a gateway with per-partner authentication, scoping, and quota enforcement","Publishing the internal APIs directly to the internet protected only by an obscure URL path","Sharing internal service credentials with each partner so they can call the APIs as employees"], correct:1, explanation:"A gateway with per-partner auth, scoping, and quotas exposes only intended APIs; full VPN, obscure URLs, and shared credentials over-expose internal systems." },
  { id:70939, domain:1, level:2, question:"Which control best prevents privilege escalation through misconfigured cloud IAM trust relationships?", options:["Granting wildcard permissions on all roles so that no legitimate action is ever blocked at all whenever the situation arises","Allowing any principal in the account to assume any role to reduce friction for developers","Regularly analyzing IAM policies with automated tooling to detect over-permissive role assumptions","Reviewing IAM only once at account creation and never reassessing it as the environment grows"], correct:2, explanation:"Automated IAM analysis detects risky trust paths; wildcard grants, open role assumption, and one-time review enable escalation." },
  { id:70940, domain:1, level:3, question:"A high-security design must ensure backups themselves cannot be encrypted or deleted by ransomware. Which approach is strongest?", options:["Storing backups on the same writable share that the production servers mount continuously","Keeping a single backup copy on a network drive that all administrators can modify freely","Relying on the production storage snapshots that share the same access controls as the live data as the architecture currently stands","Immutable, air-gapped backup copies with object lock and separate credentials from production systems"], correct:3, explanation:"Immutable, air-gapped backups with object lock and separate credentials resist ransomware; shared writable shares, single mutable copies, and same-control snapshots can be destroyed." },
  { id:70941, domain:1, level:2, question:"Which architectural approach best reduces the attack surface of a public-facing application's administrative interface?", options:["Restricting the admin interface to a private network reachable only through brokered, authenticated access","Publishing the admin interface on the same public URL as the application with a longer password","Hiding the admin interface on a nonstandard high port while leaving it open to the entire internet during day-to-day operations","Allowing admin access from any source as long as the request includes a custom HTTP header value"], correct:0, explanation:"Confining admin interfaces to private, brokered access shrinks attack surface; public exposure, port obscurity, and header tricks remain reachable by attackers." },
  { id:70942, domain:1, level:3, question:"An architect must design tamper-evident audit logging for a regulated workload. Which mechanism provides cryptographic assurance of log integrity?", options:["A plain text log file that administrators promise not to edit unless absolutely necessary later in the scenario being described","A hash-chained or append-only log with periodic signed checkpoints stored independently of producers","A database table where rows can be updated freely but a last-modified timestamp is recorded","Compressing logs nightly so that any modification would change the resulting archive file size"], correct:1, explanation:"Hash-chaining with signed checkpoints gives tamper evidence; editable text files, mutable rows, and compression do not cryptographically prove integrity." },
  { id:70943, domain:1, level:2, question:"Which design best supports secure multi-tenancy when strong isolation between tenants is required?", options:["A single shared database table where tenant rows are distinguished only by a tenant identifier column over the lifetime of the system","One shared encryption key for all tenants so that key management remains simple and inexpensive","Dedicated isolated infrastructure or strong logical isolation with separate keys and access boundaries per tenant","Allowing application code alone to filter tenant data with no enforced boundary at the data layer"], correct:2, explanation:"Strong isolation with per-tenant keys and boundaries protects multi-tenancy; shared tables, shared keys, and app-only filtering risk cross-tenant leakage." },
  { id:70944, domain:1, level:1, question:"Which component terminates TLS and forwards requests to backend servers while applying security policy?", options:["A recursive DNS resolver that answers name lookups for internal client devices in most real deployments","A DHCP server that assigns IP addresses to hosts as they join the network","A syslog collector that aggregates event messages from many different sources","A reverse proxy positioned in front of the backend application servers it protects"], correct:3, explanation:"A reverse proxy terminates TLS and enforces policy in front of backends; resolvers, DHCP, and syslog collectors serve unrelated functions." },
  { id:70945, domain:1, level:3, question:"A company wants to apply zero trust to a legacy application that cannot do modern authentication. Which approach bridges the gap?", options:["Fronting the legacy app with an identity-aware proxy that enforces authentication and authorization externally","Exposing the legacy app directly and trusting the corporate firewall to keep attackers away from it under typical operating conditions","Rewriting the entire legacy application from scratch before any users are allowed to access it","Disabling authentication on the legacy app entirely since it cannot support modern standards anyway"], correct:0, explanation:"An identity-aware proxy enforces zero-trust controls externally without rewriting the app; direct exposure, full rewrites, or disabling auth are unsafe or impractical." },
  { id:70946, domain:1, level:2, question:"Which control most effectively prevents data leakage through misconfigured public cloud storage?", options:["Relying on each engineer to remember to set the correct permissions every time a bucket is made across the affected systems","Account-level public access blocks combined with automated configuration scanning and remediation","Allowing public access by default and trusting that sensitive data will never be placed there","Auditing storage permissions once a year during the annual compliance certification exercise"], correct:1, explanation:"Account-wide public access blocks plus continuous scanning prevent exposure; human memory, permissive defaults, and yearly audits leave long windows of risk." },
  { id:70947, domain:1, level:3, question:"An enterprise needs to verify integrity of its software supply chain at deploy time. Which architectural control is most effective?", options:["Trusting any artifact that successfully builds in the pipeline without checking who produced it for the foreseeable future","Scanning only the final running container for malware after it is already live in production","Enforcing signed provenance attestations (such as SLSA) verified by an admission policy before deployment","Allowing direct uploads of artifacts to production from developer laptops to speed releases up"], correct:2, explanation:"Verifying signed provenance attestations at admission ensures supply-chain integrity; trusting any build, post-deploy scanning, and laptop uploads leave gaps." },
  { id:70948, domain:1, level:2, question:"Which architectural choice best balances usability and security for workforce access to internal web apps?", options:["A separate username and password for each application with no central identity coordination at all throughout the whole environment","One shared team login per application to reduce the number of credentials people must remember","Unauthenticated internal access on the assumption that the office network is inherently trusted","Single sign-on with adaptive MFA and an identity-aware access proxy enforcing per-app authorization"], correct:3, explanation:"SSO with adaptive MFA behind an access proxy balances usability and security; per-app passwords, shared logins, and unauthenticated access weaken or burden security." },
  { id:70949, domain:2, level:3, question:"During threat hunting an analyst sees a host beaconing to a domain at 60-second intervals with jittered payload sizes. Which hypothesis fits and how is it confirmed?", options:["Likely command-and-control beaconing; confirm by correlating DNS, proxy logs, and TLS JA3 fingerprints over time","Routine NTP time synchronization; confirm simply by checking the host's current clock drift values","Normal software update polling; confirm by reading the end-user license agreement of installed apps in practice as well as in theory","Printer discovery broadcast traffic; confirm by counting the active jobs sitting in the print queue"], correct:0, explanation:"Regular jittered beaconing suggests C2; correlating DNS, proxy, and TLS fingerprints validates it, while NTP, updates, and printing do not explain jittered payloads." },
  { id:70950, domain:2, level:2, question:"An incident responder must preserve volatile data on a live compromised server before isolating it. Which collection order follows order of volatility?", options:["Disk images first, then archived backups, then system RAM, and finally the CPU cache at the very end according to the proposed plan","CPU registers and cache first, then RAM, then network connection state, then disk artifacts last of all","Email archives first, then printed reports, then RAM contents, and the CPU registers captured last","Cloud billing records first, then RAM, then CPU registers, and the ARP cache collected at the end"], correct:1, explanation:"Order of volatility collects the most ephemeral data (registers, cache, RAM, network state) before disk; starting with disk or backups loses volatile evidence." },
  { id:70951, domain:2, level:3, question:"A SOC sees thousands of failed logins from rotating IPs followed by a few successes. Which logic distinguishes credential stuffing from brute force?", options:["Alert only when a single source IP exceeds one thousand failures against one particular account whenever the situation arises","Block any login attempt that simply occurs outside of the organization's normal business hours","Correlate reuse of the same valid username and password pairs across many accounts from distributed sources","Trigger an alert solely when the submitted password is shorter than twelve characters in length"], correct:2, explanation:"Credential stuffing reuses leaked valid pairs across many accounts from many IPs; single-IP-per-account thresholds catch brute force, not distributed stuffing." },
  { id:70952, domain:2, level:2, question:"An organization wants to reduce SIEM alert fatigue. Which approach improves signal without dropping coverage?", options:["Disabling all of the medium and low severity rules permanently across the entire SIEM platform","Forwarding every single raw log line directly to analysts with no aggregation or correlation","Increasing the alert email frequency so that the team is certain never to miss any event at all as the architecture currently stands","Tuning detection rules with risk-based scoring and enriching alerts with asset and identity context"], correct:3, explanation:"Risk-based scoring plus enrichment prioritizes meaningful alerts while keeping coverage; blanket disabling drops coverage and raw forwarding worsens fatigue." },
  { id:70953, domain:2, level:3, question:"A forensic analyst recovers a deleted file and must prove it was not altered after acquisition. Which practice provides that assurance?", options:["Computing and documenting a cryptographic hash of the image at acquisition and re-verifying it later","Storing the original drive inside a locked drawer without keeping any documentation of the process during day-to-day operations","Renaming the recovered evidence file to include the analyst's initials and the current date stamp","Opening the recovered file in a text editor to visually confirm that the contents look correct"], correct:0, explanation:"A documented hash at acquisition, re-verified later, proves integrity; physical storage alone, renaming, or opening the file do not prove non-alteration." },
  { id:70954, domain:2, level:1, question:"Which SOC function proactively searches for threats that evade existing automated detections?", options:["Patch management that tracks and deploys vendor updates across the organization's endpoints in the scenario being described","Threat hunting performed by analysts forming and testing hypotheses against available telemetry","License auditing that reconciles installed software against purchased entitlement records","Help desk triage that routes routine user support tickets to the appropriate support teams"], correct:1, explanation:"Threat hunting proactively seeks undetected adversary activity; patching, licensing, and help desk triage are not proactive threat discovery functions." },
  { id:70955, domain:2, level:2, question:"An IR team contains a ransomware outbreak by isolating affected segments. Which next step supports both recovery and root-cause analysis?", options:["Immediately wipe and rebuild every affected host to restore service to users as fast as possible over the lifetime of the system","Pay the ransom to obtain the decryption key and then resume normal business operations quickly","Preserve forensic images of representative affected hosts before reimaging or restoring any systems","Delete all of the logs from the affected segment to prevent any possible reinfection vectors"], correct:2, explanation:"Imaging representative hosts preserves evidence before recovery; wiping everything or deleting logs destroys evidence, and paying does not address root cause." },
  { id:70956, domain:2, level:3, question:"A detection engineer maps coverage to MITRE ATT&CK and finds a gap in T1055 process injection. Which telemetry closes it?", options:["Perimeter firewall logs showing which outbound ports were allowed through the network edge","Quarterly vulnerability scan reports covering the organization's public-facing internet assets in most real deployments","Badge reader records drawn from the data center's physical access control system overnight","Endpoint detection sensors capturing process creation, memory operations, and API call sequences"], correct:3, explanation:"Process injection is observed via EDR process/memory/API telemetry; firewall, scan, and badge data lack the host-level visibility needed for T1055." },
  { id:70957, domain:2, level:2, question:"After a phishing compromise an analyst must determine the blast radius of a stolen OAuth token. Which step is most informative?", options:["Reviewing the identity provider's sign-in and consent logs for all actions performed with that token","Rebooting the affected user's workstation to clear any cached browser sessions that may remain","Resetting the affected user's desk phone voicemail PIN as a general precautionary measure today under typical operating conditions","Checking the office wireless signal strength near the affected user's desk during the incident"], correct:0, explanation:"IdP sign-in and consent logs reveal what the token accessed and authorized; rebooting, voicemail PINs, and Wi-Fi strength reveal nothing about token misuse." },
  { id:70958, domain:2, level:3, question:"A SOC wants to automate response to confirmed malicious IPs. Which SOAR design minimizes disruption of legitimate traffic?", options:["Automatically null-route any IP that appears even once in a single low-severity informational alert across the affected systems","Enrich and score indicators, gate high-impact blocks behind approval, and auto-block only high-confidence matches","Block every IP originating from a particular foreign country regardless of any observed behavior","Disable all automation entirely and instead handle each indicator manually through phone calls"], correct:1, explanation:"Enrichment, confidence thresholds, and approval gates prevent disruptive false blocks; single-alert auto-blocking and geo-blocking cause collateral damage." },
  { id:70959, domain:2, level:3, question:"An analyst investigating suspected data exfiltration sees large encrypted uploads to a cloud storage provider at night. Which action best confirms malicious intent?", options:["Immediately blocking all cloud storage providers across the organization without any further analysis for the foreseeable future","Assuming the activity is benign because the traffic is encrypted and therefore probably legitimate","Correlating the destination, account, and data volume against the user's baseline and approved business use","Waiting several weeks to see whether the same pattern repeats before taking any investigative action"], correct:2, explanation:"Baseline correlation distinguishes malicious exfiltration from sanctioned use; blanket blocking is disruptive, encryption does not imply benign, and waiting risks ongoing loss." },
  { id:70960, domain:2, level:2, question:"Which artifact is most valuable for reconstructing the timeline of an attacker's actions on a Windows host?", options:["A single screenshot of the desktop taken by the user at the moment they noticed the problem throughout the whole environment","The antivirus marketing brochure describing the product features installed on the endpoint","A verbal recollection from the user about roughly when they thought something seemed wrong","Correlated event logs, prefetch, registry, and EDR process telemetry aligned to a common time source"], correct:3, explanation:"Correlated logs, prefetch, registry, and EDR telemetry reconstruct a timeline; a screenshot, brochure, or vague recollection are not reliable forensic sources." },
  { id:70961, domain:2, level:3, question:"A threat hunter wants to detect living-off-the-land attacks using built-in administrative tools. Which detection strategy is most effective?", options:["Baselining normal use of native binaries and alerting on anomalous parent-child process and command-line patterns","Blocking the use of all built-in operating system utilities for every user across the enterprise","Relying solely on file-hash signatures since the malicious tools are already on every system anyway in practice as well as in theory","Ignoring native tool usage because legitimate administrators also use those same utilities daily"], correct:0, explanation:"Baselining and alerting on anomalous process lineage and command lines catches LOLBins; blocking native tools is impractical, hashes miss legitimate binaries, and ignoring usage misses the attack." },
  { id:70962, domain:2, level:2, question:"During incident response, which practice best maintains chain of custody for collected digital evidence?", options:["Letting any team member borrow the evidence drive as needed without recording who took it","Documenting each transfer of evidence with handler, time, and purpose in a continuous custody record","Storing evidence in a shared open cabinet so that responders can grab items when convenient","Relabeling evidence items after the fact based on memory once the investigation has concluded according to the proposed plan"], correct:1, explanation:"A continuous custody record of every transfer maintains chain of custody; uncontrolled borrowing, open storage, and after-the-fact relabeling break it." },
  { id:70963, domain:2, level:3, question:"A SOC receives an alert that a service account is authenticating from a new geographic region at an unusual hour. Which response is most appropriate first?", options:["Immediately delete the service account to stop the activity without checking what depends on it whenever the situation arises","Ignore the alert because service accounts often authenticate from many regions during the day","Validate against the account's expected behavior and recent change tickets before disabling or escalating it","Email the entire company warning that the service account has definitely been fully compromised"], correct:2, explanation:"Validating against expected behavior and change records avoids both overreaction and neglect; deleting blindly causes outages, ignoring misses compromise, and mass email is premature." },
  { id:70964, domain:2, level:2, question:"Which capability most improves an organization's ability to respond consistently to recurring incident types?", options:["A single senior responder who personally remembers how each past incident was handled","An expectation that responders will improvise correctly under pressure during every event","A policy stating that incidents should be resolved quickly without any further detail given","Documented and tested incident response playbooks tailored to common scenarios and roles"], correct:3, explanation:"Tested playbooks ensure consistent, repeatable response; reliance on one person's memory, improvisation, or vague policy yields inconsistent outcomes." },
  { id:70965, domain:2, level:3, question:"An analyst suspects a kerberoasting attack in an Active Directory environment. Which indicator best supports this hypothesis?", options:["A single account requesting many service tickets with weak encryption types in a short time window","A spike in successful interactive logons to the organization's public marketing website overnight during day-to-day operations","An increase in the number of password reset requests submitted through the IT help desk portal","A rise in outbound email volume from the finance department during the end-of-quarter close"], correct:0, explanation:"Bulk service-ticket requests with weak encryption indicate kerberoasting; website logons, help desk resets, and email volume are unrelated to Kerberos ticket abuse." },
  { id:70966, domain:2, level:2, question:"Which metric best measures how quickly a SOC identifies that an incident is occurring?", options:["The total number of security tools that the SOC has purchased and deployed in the environment","Mean time to detect, measured from the start of malicious activity to its identification by the team","The count of newsletters the security team distributes to staff during each calendar quarter","The number of conference talks the SOC leadership delivers at industry events every single year in the scenario being described"], correct:1, explanation:"Mean time to detect measures identification speed; tool counts, newsletters, and conference talks do not reflect detection performance." },
  { id:70967, domain:2, level:3, question:"A responder must determine whether a malicious binary established persistence on a Linux host. Which locations should be examined first?", options:["The kernel version string and the system uptime counter reported by the operating system today","The total amount of free disk space remaining on the root filesystem at the time of analysis","Cron jobs, systemd units, shell init files, and modified service binaries for unauthorized changes","The font rendering settings configured for the graphical desktop environment of the logged-in user"], correct:2, explanation:"Cron, systemd, init files, and altered service binaries are common Linux persistence sites; kernel version, disk space, and font settings are irrelevant to persistence." },
  { id:70968, domain:2, level:2, question:"Which approach best enables a SOC to detect threats it has not previously seen signatures for?", options:["A static blocklist of known-bad file hashes refreshed only once every several months at most","An assumption that any traffic which passed the firewall is automatically safe and benign","Reliance on users to report when they personally feel that something on their device is wrong in most real deployments","Behavioral analytics that flag anomalous deviations from established baselines of normal activity"], correct:3, explanation:"Behavioral analytics detect novel threats by spotting deviations; stale hash lists, firewall-passed assumptions, and user reports miss unknown attacks." },
  { id:70969, domain:2, level:3, question:"An organization wants to validate its detection and response capabilities against realistic adversary behavior. Which exercise is most appropriate?", options:["A purple team engagement where red team techniques are executed and blue team detections are measured","A vulnerability scan of the external perimeter that simply lists the missing software patches under typical operating conditions","A tabletop discussion about hypothetical scenarios with no technical actions executed at all","An automated penetration test that only checks for default credentials on network devices"], correct:0, explanation:"A purple team engagement directly tests detection and response against real techniques; scans list flaws, tabletops are discussion-only, and limited pen tests have narrow scope." },
  { id:70970, domain:2, level:2, question:"During triage, which factor most appropriately drives the priority assigned to a security alert?", options:["The alphabetical order of the hostname involved in the alert as it appears in the console","The business impact and asset criticality combined with the confidence that the alert is a true positive","The personal preference of whichever analyst happens to pick up the alert from the queue first across the affected systems","The color that the SIEM vendor chose to display for that particular alert category by default"], correct:1, explanation:"Business impact, asset criticality, and confidence drive sound prioritization; hostname order, analyst whim, and display color are arbitrary." },
  { id:70971, domain:2, level:3, question:"A hunt reveals an attacker using WMI for lateral movement. Which data source most directly detects this technique?", options:["Monthly antivirus definition update timestamps gathered from each managed endpoint device","The data center temperature and humidity readings recorded by environmental sensors hourly for the foreseeable future","WMI activity and remote process-creation logs correlated with authentication events across hosts","The corporate VPN client version installed on remote employees' personal home computers"], correct:2, explanation:"WMI and remote process-creation logs with auth correlation detect WMI lateral movement; AV update times, environmental readings, and VPN versions are unrelated." },
  { id:70972, domain:2, level:2, question:"Which practice best ensures lessons from an incident actually improve future security posture?", options:["Closing the incident ticket immediately and moving on to the next item in the work queue","Discussing the incident informally at lunch without recording any decisions or follow-up tasks throughout the whole environment","Assuming the same incident will simply not happen again now that everyone is more aware","A structured post-incident review producing tracked action items with owners and verification of completion"], correct:3, explanation:"A structured review with tracked, owned, verified action items drives improvement; closing quickly, informal chats, and assumptions yield no durable change." },
  { id:70973, domain:2, level:3, question:"An analyst observes encoded PowerShell with hidden window flags spawned by a document reader process. What is the best interpretation?", options:["Likely malicious macro-driven execution; investigate the parent document, encoded payload, and outbound connections","A normal system maintenance task that always runs encoded commands from the document reader","An expected behavior of the office suite that should be added to an allowlist without review","A harmless user action that requires no further investigation because the document opened fine in practice as well as in theory"], correct:0, explanation:"Encoded hidden PowerShell from a document reader strongly suggests malicious macros; treating it as normal maintenance, expected behavior, or harmless ignores a likely compromise." },
  { id:70974, domain:2, level:2, question:"Which is the most appropriate first containment action when a workstation is confirmed to be actively communicating with an attacker?", options:["Power the host off immediately to be safe, discarding any volatile memory evidence in the process","Network-isolate the host while preserving it powered on to retain volatile memory and active connections","Leave the host fully connected and simply watch the attacker to gather more intelligence indefinitely according to the proposed plan","Reimage the host right away before capturing any forensic data about the ongoing intrusion at all"], correct:1, explanation:"Network isolation while keeping the host powered preserves volatile evidence and stops attacker comms; powering off, leaving it connected, or reimaging first loses evidence or prolongs risk." },
  { id:70975, domain:2, level:3, question:"A SOC wants earlier warning of attacks targeting its sector. Which intelligence practice is most useful?", options:["Reading general technology news headlines occasionally when an analyst happens to have free time","Waiting for the organization's own systems to be attacked before learning the adversary techniques whenever the situation arises","Consuming and operationalizing sector-specific threat intelligence into detections and hunting hypotheses","Collecting threat reports into a folder that nobody ever opens or turns into actionable detections"], correct:2, explanation:"Operationalizing sector intelligence into detections and hunts gives early warning; passive news reading, waiting to be attacked, and unread reports provide little value." },
  { id:70976, domain:2, level:2, question:"Which log source is most directly useful for detecting unauthorized changes to cloud infrastructure?", options:["The application's user-facing access log showing which web pages site visitors requested","The marketing analytics platform tracking how customers move through the public website funnel as the architecture currently stands","The office building's HVAC controller log recording temperature setpoints throughout the day","The cloud provider's API audit log recording who performed which control-plane actions and when"], correct:3, explanation:"Cloud control-plane audit logs reveal who changed infrastructure; app access logs, marketing analytics, and HVAC logs do not capture cloud configuration changes." },
  { id:70977, domain:2, level:3, question:"A forensic investigator must analyze a disk image without altering the original evidence. Which technique is standard practice?", options:["Working from a verified bit-for-bit copy mounted read-only through a hardware or software write blocker","Booting the suspect drive directly into its installed operating system to browse the files normally during day-to-day operations","Editing files on the original drive while taking careful notes about each change that is made","Defragmenting the original drive first so that the files are easier to locate during analysis"], correct:0, explanation:"Analyzing a verified copy through a write blocker preserves the original; booting, editing, or defragmenting the original alters evidence and breaks integrity." },
  { id:70978, domain:2, level:2, question:"Which capability best helps a SOC correlate related alerts into a single coherent incident?", options:["A rule that automatically closes any alert that has not been reviewed within twenty-four hours","A SIEM or XDR platform that links events across sources by entity, time, and attack technique","A separate inbox for each individual security tool so analysts can check them one at a time","A policy requiring analysts to manually compare every alert against every other alert by hand"], correct:1, explanation:"Correlation by entity, time, and technique groups related alerts; auto-closing, siloed inboxes, and fully manual comparison fragment or overwhelm investigation." },
  { id:70979, domain:2, level:3, question:"An analyst finds a scheduled task that downloads and executes content from a pastebin URL every hour. What is the most likely conclusion?", options:["A standard operating system update routine that always fetches its patches from pastebin services over the lifetime of the system","A legitimate backup job because it runs on a regular hourly schedule like many backup tools do","A likely persistence and staging mechanism for malware; analyze the task, the URL content, and execution history","A harmless developer convenience that should be left in place since it has not caused errors yet"], correct:2, explanation:"An hourly task pulling and running pastebin content is a classic persistence/staging pattern; OS updates do not use pastebin and the regular schedule does not make it benign." },
  { id:70980, domain:2, level:2, question:"Which approach most improves the reliability of timestamps across logs during an investigation?", options:["Letting each server keep whatever local clock it had with no synchronization between systems","Manually estimating event times after the fact based on when the analyst noticed the activity","Recording only the date of each event and omitting the time to keep the logs simpler to read","Synchronizing all systems to a trusted time source and recording the time zone for each event"], correct:3, explanation:"Synchronized trusted time and recorded zones make cross-log correlation reliable; unsynchronized clocks, estimates, and date-only logs undermine timeline accuracy." },
  { id:70981, domain:2, level:3, question:"A SOC must reduce dwell time for advanced intrusions. Which combination most directly achieves this?", options:["Continuous monitoring with behavioral detection, proactive hunting, and rehearsed rapid response procedures","An annual penetration test report reviewed once and then filed away until the following year","A longer log retention period alone, without any change to how the logs are actively analyzed","More frequent password rotation for end users without any improvement to detection capabilities under typical operating conditions"], correct:0, explanation:"Continuous behavioral monitoring, hunting, and rehearsed response cut dwell time; annual tests, mere retention, and password rotation do not speed detection or response." },
  { id:70982, domain:2, level:2, question:"Which is the most appropriate use of an indicator of compromise during an investigation?", options:["Publishing the indicator publicly with the victim's name before the investigation is complete","Searching historical and live telemetry for the indicator to scope the breadth of the compromise","Treating a single indicator as definitive proof of attribution to a specific named threat actor","Ignoring the indicator because indicators change frequently and are therefore not worth checking"], correct:1, explanation:"Sweeping telemetry for an IoC scopes the compromise; premature public disclosure, over-confident attribution, and ignoring indicators are inappropriate uses." },
  { id:70983, domain:2, level:3, question:"An analyst sees an internal host scanning many internal ports across multiple subnets. Which conclusion and action are most appropriate?", options:["Normal network discovery that should always be ignored because internal scanning is harmless","A misconfigured printer searching for supplies, so no security investigation is warranted at all for the foreseeable future","Probable internal reconnaissance; isolate the host, investigate the source process, and check for prior compromise","An expected backup process, so the scanning host should simply be added to an allowlist quickly"], correct:2, explanation:"Internal port sweeping across subnets signals reconnaissance and warrants isolation and investigation; dismissing it as harmless, a printer, or backup risks missing active compromise." },
  { id:70984, domain:2, level:2, question:"Which detection approach is most resilient to attackers who frequently change their malware's file hashes?", options:["Maintaining an ever-growing list of every individual file hash the team has ever encountered","Blocking files based only on their file names since attackers rarely change those between samples throughout the whole environment","Trusting any executable that is digitally signed without verifying who actually signed it or why","Detecting on behaviors and techniques such as suspicious process lineage rather than on file hashes alone"], correct:3, explanation:"Behavioral and technique-based detection survives hash changes; hash lists, filename blocking, and blind trust of signatures are easily evaded." },
  { id:70985, domain:2, level:3, question:"During cloud incident response, an attacker created new IAM access keys for a compromised user. Which response best limits further damage while preserving evidence?", options:["Disable the malicious keys and the user, snapshot relevant logs, then review all actions taken with those keys","Delete the entire account immediately so no trace of the attacker's activity remains anywhere","Leave the keys active to avoid alerting the attacker while taking no other action for several days","Rotate only the user's console password while leaving the attacker-created access keys fully active in practice as well as in theory"], correct:0, explanation:"Disabling malicious keys and the user, snapshotting logs, and reviewing actions limits damage and preserves evidence; deletion destroys evidence, inaction prolongs access, and password-only rotation leaves keys working." },
  { id:70986, domain:2, level:2, question:"Which practice best supports effective communication during a major incident?", options:["Allowing every responder to message executives directly with their own informal status updates","A predefined communication plan with roles, escalation paths, and approved channels for stakeholders","Withholding all information from leadership until the incident is fully and completely resolved","Posting raw technical details to a public social media account as the investigation unfolds live according to the proposed plan"], correct:1, explanation:"A predefined communication plan keeps messaging coordinated; ad hoc executive messages, total silence, and public posting create confusion or harm." },
  { id:70987, domain:2, level:3, question:"A threat hunter wants to find compromised credentials being used from anomalous infrastructure. Which analytic is most effective?", options:["Counting the total number of successful logins per day without considering where they came from whenever the situation arises","Alerting only when a user manually reports that they believe their password has been stolen","Impossible-travel and infrastructure-anomaly analysis correlating authentications with geolocation and ASN data","Reviewing physical badge swipes at the building entrance to infer who is using each account"], correct:2, explanation:"Impossible-travel and ASN anomaly analytics surface stolen-credential misuse; raw login counts, self-reports, and badge swipes do not correlate authentication with infrastructure." },
  { id:70988, domain:2, level:1, question:"Which is the primary purpose of containment in the incident response lifecycle?", options:["Permanently eliminating every trace of the attacker before any analysis can be performed at all","Restoring all affected systems to production immediately regardless of whether the threat remains as the architecture currently stands","Assigning blame to the individual employee whose account was involved in the initial intrusion","Limiting the spread and impact of an incident while preserving the ability to investigate it further"], correct:3, explanation:"Containment limits spread and impact while enabling investigation; eradication and recovery come later, and blame assignment is not a phase goal." },
  { id:70989, domain:2, level:3, question:"An analyst must decide whether a flagged binary is malicious before it spreads. Which combination of techniques gives the most reliable verdict quickly?", options:["Static analysis, sandbox detonation, and reputation lookups correlated to reach a confident assessment","Asking the user who downloaded it whether they personally think the file looks dangerous or not","Checking only the file extension and trusting that an executable extension means it must be malware during day-to-day operations","Renaming the file and rerunning it to see whether the new name changes its observed behavior"], correct:0, explanation:"Combining static analysis, sandboxing, and reputation yields a reliable verdict; user opinion, extension-only checks, and renaming do not assess behavior or intent." },
  { id:70990, domain:2, level:2, question:"Which artifact best helps an investigator determine which external hosts a compromised machine contacted?", options:["The desktop wallpaper image that was set on the machine at the time it was first imaged","Network flow records and DNS resolution logs covering the relevant time window of the incident","A list of the fonts that happened to be installed in the operating system's font directory","The screen brightness level that the user had configured before the incident was first noticed"], correct:1, explanation:"Flow records and DNS logs reveal contacted hosts; wallpaper, font lists, and brightness settings carry no network communication information." },
  { id:70991, domain:2, level:3, question:"A SOC integrating deception technology wants high-fidelity alerts. Why are well-placed honeytokens valuable?", options:["They automatically patch the vulnerabilities that attackers attempt to exploit during an intrusion over the lifetime of the system","They generate large volumes of routine traffic that analysts must sift through every single day","Any interaction with a honeytoken is inherently suspicious, producing very low false-positive detections","They replace the need for any other monitoring because attackers always trigger them every time"], correct:2, explanation:"Honeytokens generate high-fidelity alerts because legitimate users have no reason to touch them; they do not patch flaws, create noise, or replace other monitoring." },
  { id:70992, domain:2, level:2, question:"Which approach best validates that backups are actually usable for recovery after a destructive incident?", options:["Confirming only that the backup job reported success in the scheduler without ever restoring it","Assuming the backups are good because the storage device shows that free space is decreasing","Checking the backup file sizes once and trusting they remain valid indefinitely afterward forever in most real deployments","Performing regular restore tests that verify integrity and recovery time against defined objectives"], correct:3, explanation:"Regular restore testing proves backups are usable and meet objectives; job-success messages, free-space changes, and file-size checks do not verify recoverability." },
  { id:70993, domain:2, level:3, question:"An analyst observes a sudden surge of outbound traffic to many random high ports immediately after a vulnerability was disclosed. What is the most likely scenario?", options:["Possible mass exploitation and beaconing from newly compromised hosts; isolate, scope, and hunt for the foothold","A routine software update that always uses thousands of random high ports during installation","Normal peer-to-peer file sharing that employees commonly run on the corporate network at night","A harmless coincidence unrelated to the disclosure that requires no investigative action at all under typical operating conditions"], correct:0, explanation:"A surge of random high-port outbound traffic right after disclosure suggests mass exploitation; updates do not behave this way, and dismissing it as P2P or coincidence risks missing a breach." },
  { id:70994, domain:2, level:2, question:"Which is the most appropriate role of an EDR tool during incident response?", options:["Serving as the organization's primary firewall to filter all inbound internet traffic at the edge","Providing host visibility, isolating endpoints, and enabling remote investigation and remediation actions","Acting as the system of record for employee payroll and human resources information for the company across the affected systems","Replacing the need for any backups by guaranteeing that ransomware can never encrypt any files"], correct:1, explanation:"EDR gives host visibility, isolation, and remote remediation; it is not a perimeter firewall, an HR system, or a backup replacement." },
  { id:70995, domain:2, level:3, question:"A responder needs to determine whether stolen data actually left the environment. Which evidence most directly answers this?", options:["The number of files that were present on the affected host at the time of the initial discovery for the foreseeable future","The CPU utilization graph of the affected host averaged over the previous thirty calendar days","Egress flow and proxy logs showing volume and destination of outbound transfers from the affected hosts","The list of USB devices that were connected to unrelated machines elsewhere in the organization"], correct:2, explanation:"Egress flow and proxy logs reveal whether and where data was transferred out; file counts, CPU graphs, and unrelated USB lists do not confirm exfiltration." },
  { id:70996, domain:2, level:2, question:"Which practice most reduces the chance that an attacker's actions go unnoticed in cloud environments?", options:["Logging only failed actions and discarding successful ones to save on storage costs over time","Keeping logs solely within the compromised account where an attacker could simply delete them","Disabling logging during business hours so that normal activity does not fill up the log store throughout the whole environment","Enabling comprehensive control-plane and data-plane logging and forwarding it to a monitored SIEM"], correct:3, explanation:"Comprehensive logging forwarded to a monitored, separate SIEM ensures visibility; success-only gaps, in-account logs, and disabled logging let attackers hide." },
  { id:70997, domain:3, level:3, question:"An engineer must protect data in use in a multi-tenant cloud so even the provider cannot read it during processing. Which technology fits best?", options:["Confidential computing using hardware-based trusted execution environments to isolate data during processing","Standard TLS 1.3 termination performed at the cloud provider's shared load balancer tier only","AES-256 encryption applied to the data solely while it rests inside object storage buckets","Database column masking that is applied only after the query results are returned to the client in practice as well as in theory"], correct:0, explanation:"Confidential computing isolates data in hardware enclaves during processing; TLS protects transit, and at-rest encryption or masking do not protect data in use." },
  { id:70998, domain:3, level:2, question:"A PKI design requires that compromise of one issuing CA does not invalidate the entire trust chain. Which architecture achieves this?", options:["A single online root CA that directly issues every end-entity certificate across the enterprise","An offline root CA that issues to multiple purpose-scoped intermediate CAs for different uses","A flat design where all of the servers share one common self-signed certificate everywhere","Distributing copies of the root private key to every regional administrator for convenience"], correct:1, explanation:"An offline root with scoped intermediates contains the blast radius of an intermediate compromise; a single online root or shared key concentrates risk." },
  { id:70999, domain:3, level:3, question:"An application must verify message integrity and authenticity between two parties sharing a secret. Which primitive is most appropriate?", options:["A plain SHA-256 hash of the message transmitted alongside the message over the same channel","Base64 encoding of the message applied before it is sent across the network to the receiver","An HMAC computed over the message using the pre-shared secret key known to both parties","A CRC32 checksum appended to the message only to detect accidental transmission corruption"], correct:2, explanation:"HMAC provides integrity and authenticity via a keyed hash; a plain hash or CRC offers no authenticity, and Base64 is encoding, not protection." },
  { id:71000, domain:3, level:2, question:"A team migrating to TLS 1.3 wants forward secrecy. Which configuration guarantees it?", options:["Reusing a single static RSA key to encrypt the premaster secret for better handshake performance as the architecture currently stands","Disabling certificate validation entirely in order to speed up the overall handshake process","Hardcoding one shared session key that is reused across every client connection to the server","Using ephemeral elliptic-curve Diffie-Hellman key exchange so session keys derive from per-session secrets"], correct:3, explanation:"Ephemeral ECDHE gives forward secrecy with per-session keys; static RSA key transport, disabled validation, or fixed keys break it." },
  { id:71001, domain:3, level:3, question:"An organization plans for post-quantum readiness. Which interim strategy best protects long-lived secrets from harvest-now-decrypt-later attacks?", options:["Deploying hybrid key exchange that combines a classical algorithm with a post-quantum key encapsulation mechanism","Increasing RSA key length to 1024 bits to improve its resistance against future quantum attacks","Switching all hashing to MD5 simply because it is computationally faster to verify than alternatives during day-to-day operations","Relying only on perimeter firewalls to prevent any interception of the data in the first place"], correct:0, explanation:"Hybrid classical-plus-PQC key exchange hedges against future quantum decryption; 1024-bit RSA is weaker, MD5 is broken, and firewalls do not stop captured ciphertext." },
  { id:71002, domain:3, level:2, question:"A developer needs to store user passwords securely. Which approach best resists offline cracking if the database is stolen?", options:["A single unsalted SHA-1 hash applied exactly once to each user's chosen password string","A memory-hard adaptive hashing function such as Argon2 applied with a unique per-user salt value","Reversible AES encryption using a key that is conveniently stored in the same database table in the scenario being described","Plaintext storage of passwords protected only by the file system permissions on the database"], correct:1, explanation:"Argon2 with per-user salts is slow and memory-hard, resisting offline cracking; unsalted SHA-1, reversible encryption with a co-located key, and plaintext fail badly." },
  { id:71003, domain:3, level:1, question:"Which property of asymmetric cryptography lets a recipient verify a sender's identity without any shared secret?", options:["Symmetric session keys that the two parties first exchange securely out of band somehow over the lifetime of the system","Hashing the message with a publicly known algorithm before sending it to the recipient","Digital signatures created with the sender's private key and verified with the public key","Encoding the message into hexadecimal format before transmitting it across the network"], correct:2, explanation:"A signature made with the sender's private key is verifiable with their public key, proving origin; symmetric keys, plain hashing, and encoding do not." },
  { id:71004, domain:3, level:3, question:"An engineer integrates a secrets manager into a CI/CD pipeline. Which practice most reduces credential leakage risk?", options:["Embedding a long-lived API key directly inside the pipeline's YAML configuration file in the repo","Printing the retrieved secrets to the build log in order to assist with debugging failed deployments","Sharing one static administrative token across every project in the entire organization for simplicity in most real deployments","Issuing short-lived dynamic credentials scoped to each individual pipeline run from the secrets manager"], correct:3, explanation:"Short-lived scoped dynamic credentials limit exposure window and blast radius; hardcoded keys, logged secrets, and shared static tokens are high-risk anti-patterns." },
  { id:71005, domain:3, level:2, question:"A certificate fails validation because the client cannot reach the OCSP responder. Which mechanism provides revocation status without that round trip?", options:["OCSP stapling, where the server presents a recent signed OCSP response during the TLS handshake","Disabling revocation checking entirely so that the connection always succeeds for every client","Extending the certificate validity period to ten years in order to avoid renewing it as often","Switching the certificate to a self-signed authority that the client is configured to simply ignore"], correct:0, explanation:"OCSP stapling lets the server attach a fresh signed status, avoiding client-to-responder calls; disabling checks or self-signing removes the security guarantee." },
  { id:71006, domain:3, level:3, question:"A design must encrypt large data volumes efficiently while still using asymmetric key distribution. Which hybrid approach is standard?", options:["Encrypt the entire large dataset directly with the recipient's RSA public key for maximum security across the affected systems","Encrypt the bulk data with a symmetric session key, then encrypt that key with the recipient's public key","Hash the data with SHA-256 and send only the resulting digest in place of the original data","Encode the data using the recipient's public key wrapped in a Base64 representation before sending"], correct:1, explanation:"Hybrid encryption uses fast symmetric crypto for bulk data and asymmetric crypto to share the key; direct RSA on bulk data is impractical, and hashing or encoding do not encrypt." },
  { id:71007, domain:3, level:3, question:"An engineer must design secure key management so that no single administrator can recover a master key alone. Which technique enforces this?", options:["Storing the full master key in a password manager that all administrators can open individually","Emailing the master key to several administrators so that at least one copy is always available","Splitting the key using secret sharing so a defined quorum of custodians is required to reconstruct it","Writing the key on a sticky note kept in a drawer that the whole team can access whenever needed for the foreseeable future"], correct:2, explanation:"Secret sharing (e.g., Shamir) requires a quorum, enforcing separation of duties; shared password managers, emailed keys, and sticky notes let one person recover the key." },
  { id:71008, domain:3, level:2, question:"Which mode of operation provides both confidentiality and integrity for encrypted data in a single primitive?", options:["Electronic codebook mode, which encrypts each block independently with the same key value used","A simple stream cipher used alone with no accompanying integrity check applied to the ciphertext throughout the whole environment","Plain CBC mode without any message authentication code attached to detect tampering afterward","An authenticated encryption mode such as AES-GCM that produces both ciphertext and an authentication tag"], correct:3, explanation:"AES-GCM is authenticated encryption providing confidentiality and integrity together; ECB, bare stream ciphers, and plain CBC lack built-in integrity." },
  { id:71009, domain:3, level:3, question:"An organization wants to ensure firmware running on its devices has not been tampered with at boot. Which mechanism provides this assurance?", options:["A measured and verified boot process anchored in a hardware root of trust that checks signatures","A startup script that prints the firmware version number to the screen during each system boot","An antivirus scan of the operating system performed several minutes after the device finishes booting","A user prompt asking the operator to confirm that the firmware looks correct before continuing on"], correct:0, explanation:"Measured/verified boot rooted in hardware validates firmware integrity before execution; printing a version, post-boot AV, and user prompts do not cryptographically verify firmware." },
  { id:71010, domain:3, level:1, question:"Which statement correctly contrasts encryption and hashing?", options:["Both encryption and hashing are reversible operations as long as the correct key is provided","Encryption is reversible with a key, while a cryptographic hash is a one-way fixed-size digest","Hashing is reversible with a key, while encryption produces an irreversible one-way digest output","Both are one-way and neither can ever be reversed under any circumstances by any party at all"], correct:1, explanation:"Encryption is reversible with a key; a cryptographic hash is one-way and fixed-size. The other options invert or confuse these fundamental properties." },
  { id:71011, domain:3, level:3, question:"A system must allow a server to prove it possesses a private key without ever transmitting that key. Which mechanism accomplishes this during TLS?", options:["Sending the private key to the client so it can independently verify that the key is valid first","Transmitting a plaintext copy of the certificate's password along with the certificate to the client whenever the situation arises","A digital signature over handshake data proving possession of the private key matching the certificate","Sharing the symmetric session key in the clear before the handshake completes for faster setup"], correct:2, explanation:"Signing handshake data proves private-key possession without revealing it; sending the key, transmitting passwords, or sharing session keys in clear are insecure and unnecessary." },
  { id:71012, domain:3, level:2, question:"Which key management practice most reduces the impact of a compromised encryption key?", options:["Using one long-lived key for all data across every system so management stays as simple as possible","Never rotating keys at all because rotation introduces operational risk that should be avoided","Storing the encryption keys alongside the encrypted data so they are always readily available","Regular key rotation combined with limiting each key's scope and cryptoperiod to reduce exposure"], correct:3, explanation:"Rotation plus scoped keys and bounded cryptoperiods limit compromise impact; one universal key, no rotation, and co-located keys maximize blast radius." },
  { id:71013, domain:3, level:3, question:"An engineer must protect an API against replay attacks where a captured signed request is resubmitted. Which control is most effective?", options:["Including a nonce and timestamp in the signed request and rejecting stale or previously seen requests","Encrypting the request body so that an attacker cannot read what the request actually contains during day-to-day operations","Compressing the request to make it smaller and therefore harder for an attacker to capture it","Sending the request over a faster network so the window for capturing it is shorter overall"], correct:0, explanation:"A signed nonce and timestamp with replay rejection defeats replay; encryption hides contents but a captured request can still be replayed, and compression or speed do not help." },
  { id:71014, domain:3, level:2, question:"Which is a primary security advantage of using an HSM for cryptographic key storage?", options:["Keys are exported to every application server in plaintext so they can be used very quickly","Keys are generated and used inside tamper-resistant hardware and never leave it in plaintext form","Keys are printed to a log file each time they are used so that operations can be easily audited in the scenario being described","Keys are emailed to administrators as backups whenever a new key is generated by the system"], correct:1, explanation:"An HSM keeps keys in tamper-resistant hardware and performs operations without exposing plaintext keys; exporting, logging, or emailing keys defeats the purpose." },
  { id:71015, domain:3, level:3, question:"A developer must securely derive multiple keys from a single shared secret. Which function is designed for this purpose?", options:["A simple XOR of the shared secret with a fixed constant value to produce each new key","Reusing the same shared secret directly for every distinct purpose without any derivation","A key derivation function such as HKDF that expands a shared secret into independent keys","Truncating the shared secret to different lengths to create what appear to be separate keys"], correct:2, explanation:"A KDF like HKDF safely derives independent keys from one secret; XOR with a constant, direct reuse, and truncation produce related, weak keys." },
  { id:71016, domain:3, level:1, question:"Which property does a digital certificate primarily bind together?", options:["A private key and the password used to unlock it, stored together for convenient retrieval later in most real deployments","A symmetric session key and the IP address of the server that will use it during connections","A user's plaintext password and their email address for the purpose of account recovery flows","A public key and the identity of its owner, attested by a trusted certificate authority's signature"], correct:3, explanation:"A certificate binds a public key to an identity via a CA signature; it does not bundle private keys with passwords, session keys with IPs, or passwords with emails." },
  { id:71017, domain:3, level:3, question:"An engineer needs to allow data to be searched while remaining encrypted at rest in an untrusted environment. Which technique enables this with tradeoffs?", options:["Searchable or deterministic encryption schemes that permit matching while concealing the underlying values","Storing the data fully in plaintext so it can be searched quickly without any encryption overhead under typical operating conditions","Hashing the data with no salt and then trying to decrypt the hashes whenever a search is run","Encrypting the data with a key that is then published openly so anyone can decrypt and search it"], correct:0, explanation:"Searchable/deterministic encryption allows matching on ciphertext with known tradeoffs; plaintext storage, salt-free hashing with decryption, and published keys are insecure." },
  { id:71018, domain:3, level:2, question:"Which control best protects the confidentiality of data transmitted over an untrusted network?", options:["Compressing the data before sending it so that eavesdroppers find it harder to interpret quickly","Encrypting the data in transit using a current TLS version with strong cipher suites configured","Sending the data over a less commonly used port in the hope that attackers will not notice it","Splitting the data across two plaintext connections so no single capture has the complete message"], correct:1, explanation:"Strong TLS encrypts data in transit, protecting confidentiality; compression, obscure ports, and split plaintext are security-through-obscurity and remain readable." },
  { id:71019, domain:3, level:3, question:"A regulated system must guarantee that a signed document's author cannot later deny signing it. Which property and mechanism provide this?", options:["Confidentiality, achieved by encrypting the document with a shared symmetric key value","Availability, achieved by replicating the document across multiple geographic regions for resilience","Non-repudiation, achieved through a digital signature created with the author's private key","Anonymity, achieved by removing all identifying information from the document before it is signed"], correct:2, explanation:"A digital signature with the author's private key provides non-repudiation; confidentiality, availability, and anonymity address different goals and do not prove authorship." },
  { id:71020, domain:3, level:2, question:"Which weakness makes ECB mode unsuitable for encrypting structured data like images?", options:["It requires an initialization vector that is impossible to generate on modern computing hardware","It is the only mode that completely prevents any form of parallel processing during encryption","It always produces ciphertext that is many times larger than the original plaintext input data","Identical plaintext blocks produce identical ciphertext blocks, revealing patterns in the data"], correct:3, explanation:"ECB maps equal plaintext blocks to equal ciphertext, leaking structure; it does not need an IV, can be parallelized, and does not inherently expand data dramatically." },
  { id:71021, domain:3, level:3, question:"An engineer must design certificate issuance for thousands of short-lived workloads. Which approach scales securely?", options:["Automated issuance of short-lived certificates tied to workload identity through an internal certificate authority","Manually generating and emailing a long-lived certificate to each workload owner one at a time","Reusing a single shared certificate across all workloads so issuance never needs to be repeated","Disabling certificates entirely and relying on static IP allowlists to identify each workload instead in practice as well as in theory"], correct:0, explanation:"Automated short-lived certs bound to workload identity scale securely; manual issuance, shared certs, and IP allowlists do not scale or provide strong identity." },
  { id:71022, domain:3, level:2, question:"Which scenario best illustrates the appropriate use of symmetric versus asymmetric cryptography together?", options:["Symmetric crypto establishes identity, then asymmetric crypto encrypts every byte for maximum speed according to the proposed plan","Asymmetric crypto establishes a shared key, then symmetric crypto encrypts the bulk session data efficiently","Asymmetric crypto encrypts all bulk data while symmetric crypto is used only to sign the messages","Both are used to hash the data twice so that the resulting digest is considered extra secure"], correct:1, explanation:"Asymmetric crypto exchanges a key and symmetric crypto encrypts bulk data efficiently; the other options misassign roles or confuse hashing with encryption." },
  { id:71023, domain:3, level:3, question:"A company wants to prevent extraction of secrets from memory dumps of a compromised application. Which engineering control helps most?", options:["Storing all secrets in a global variable for the entire runtime so they are easy to reference","Logging each secret to disk on startup so that they can be recovered if the application crashes","Minimizing secret lifetime in memory, zeroizing buffers after use, and leveraging protected key storage","Disabling all memory protections so the application runs faster and handles secrets more quickly whenever the situation arises"], correct:2, explanation:"Short secret lifetimes, zeroization, and protected key storage reduce memory exposure; global variables, disk logging, and disabled protections increase it." },
  { id:71024, domain:3, level:2, question:"Which is the main risk of using a deprecated protocol such as SSL 3.0 or early TLS?", options:["They are too computationally expensive to use on any modern server hardware available today","They are incompatible with all browsers and therefore simply will not establish any connection as the architecture currently stands","They encrypt data so strongly that legitimate administrators can no longer inspect the traffic","They contain known cryptographic weaknesses that allow attackers to decrypt or tamper with traffic"], correct:3, explanation:"Deprecated SSL/early TLS have exploitable weaknesses enabling decryption or tampering; the issue is broken security, not excessive cost, total incompatibility, or too-strong encryption." },
  { id:71025, domain:3, level:3, question:"An engineer must protect signing keys used in an automated code-signing pipeline. Which design best prevents misuse if the build server is compromised?", options:["Performing signing in an HSM or remote signing service that enforces policy and never exposes the key","Storing the signing key as a plaintext file on the build server so any job can quickly use it","Embedding the signing key inside the build container image that is pushed to a public registry","Sharing the signing key with every developer so that anyone can sign releases when they need to during day-to-day operations"], correct:0, explanation:"Remote/HSM-based signing with policy keeps keys off the build server even if it is compromised; plaintext storage, embedding in images, and broad sharing expose the key." },
  { id:71026, domain:3, level:1, question:"Which statement about salting password hashes is correct?", options:["A single shared salt for all users is just as effective as using a unique salt for each user","A unique salt per password prevents identical passwords from producing identical hashes and defeats precomputed tables","Salts must be kept secret because revealing them allows immediate recovery of the original passwords in the scenario being described","Salting is only necessary when the password database is stored on a publicly accessible web server"], correct:1, explanation:"Per-user salts prevent identical hashes and defeat rainbow tables; shared salts are weaker, salts need not be secret, and salting is always advisable, not situational." },
  { id:71027, domain:3, level:3, question:"A design must let a client verify it is talking to the genuine server and the server verify the client, both cryptographically. Which mechanism provides this?", options:["One-way TLS where only the server presents a certificate and the client remains unauthenticated","A shared password typed by the user that the server checks but the client never verifies in return","Mutual TLS, where both endpoints present and validate certificates during the handshake exchange","An IP allowlist on the server that assumes any permitted address is automatically a trusted client"], correct:2, explanation:"Mutual TLS authenticates both endpoints via certificates; one-way TLS, passwords, and IP allowlists do not provide mutual cryptographic authentication." },
  { id:71028, domain:3, level:1, question:"Which is the primary purpose of a certificate revocation list or OCSP?", options:["To increase the maximum validity period a certificate is permitted to have once it is issued","To encrypt the contents of the certificate so that only the owner can read its embedded fields in most real deployments","To distribute the private key associated with the certificate to all relying parties securely","To allow relying parties to learn that a certificate should no longer be trusted before its expiry"], correct:3, explanation:"CRLs and OCSP convey that a certificate is revoked before expiry; they do not extend validity, encrypt the certificate, or distribute private keys." },
  { id:71029, domain:3, level:3, question:"An engineer needs deterministic, collision-resistant integrity checks for large files distributed publicly. Which choice is appropriate today?", options:["A modern hash such as SHA-256 published over a trusted channel for users to verify downloads","MD5, because it remains a strong and collision-resistant choice for verifying file integrity now","A simple byte-count of the file, since two different files almost never have the same size at all","Encrypting the file with a public key so that recipients can confirm its integrity upon decryption"], correct:0, explanation:"SHA-256 over a trusted channel provides collision-resistant integrity; MD5 is broken for collisions, byte counts collide trivially, and encryption is not an integrity check." },
  { id:71030, domain:3, level:2, question:"Which approach best secures secrets used by applications running across many containers?", options:["Hardcoding the secrets into the application source code so they ship together with the binary","A centralized secrets manager that injects secrets at runtime with access tied to workload identity","Passing the secrets as plaintext command-line arguments visible in the host's process list","Storing the secrets in a publicly readable configuration file in the container's web root folder across the affected systems"], correct:1, explanation:"A central secrets manager with identity-bound runtime injection is secure; hardcoding, plaintext CLI args, and public config files expose secrets." },
  { id:71031, domain:3, level:3, question:"A team must protect a long-lived data archive whose encryption must remain strong for decades. Which engineering consideration is most important?", options:["Selecting the fastest available cipher today regardless of how it may age over coming decades","Encrypting once and assuming the chosen algorithm will remain secure forever without any review","Choosing algorithms and key sizes with long-term margins and planning for crypto-agility to swap them later","Storing the decryption key inside the archive itself so it is never lost over the long retention for the foreseeable future"], correct:2, explanation:"Long-term archives need strong margins and crypto-agility to migrate algorithms; speed-first choices, set-and-forget assumptions, and embedded keys undermine durability." },
  { id:71032, domain:3, level:1, question:"Which best describes the purpose of an initialization vector in block cipher modes like CBC?", options:["To serve as the secret key that the cipher uses to perform the actual encryption operation","To compress the plaintext before encryption so the resulting ciphertext is shorter overall","To authenticate the sender of the message so the recipient knows who created the ciphertext throughout the whole environment","To ensure that encrypting the same plaintext with the same key yields different ciphertext each time"], correct:3, explanation:"An IV randomizes ciphertext so equal plaintexts differ; it is not the key, does not compress, and does not by itself authenticate the sender." },
  { id:71033, domain:3, level:3, question:"An engineer must enable encrypted backups where compromise of the backup system alone cannot decrypt the data. Which design achieves this?", options:["Encrypting backups client-side with keys managed separately from and inaccessible to the backup system","Letting the backup system both store the data and hold the only copy of the decryption keys","Storing the backups in plaintext but restricting the file permissions on the backup server tightly in practice as well as in theory","Encrypting with a key that is written into the backup metadata so restores are fully automatic"], correct:0, explanation:"Client-side encryption with separately managed keys means the backup system cannot decrypt; co-located keys, plaintext, and embedded keys allow a single compromise to expose data." },
  { id:71034, domain:3, level:2, question:"Which is a correct reason to prefer ECDSA or EdDSA over RSA for new signing use cases?", options:["They are reversible, allowing the signature to be decrypted back into the original message content according to the proposed plan","They achieve comparable security with much smaller keys, improving performance and storage efficiency","They eliminate the need to protect the private key because the algorithm itself keeps it secret","They allow the same key pair to be safely shared publicly among many different signing parties"], correct:1, explanation:"Elliptic-curve signatures give equivalent security with smaller keys and better performance; they are not reversible, still require private-key protection, and keys must not be shared." },
  { id:71035, domain:3, level:3, question:"A design must prevent an attacker who steals a TLS session's recorded traffic from decrypting it even if the server's long-term key later leaks. Which property is required?", options:["Strong server authentication alone, since proving the server's identity protects past recorded sessions","A longer certificate validity period so the long-term key remains valid and trusted for more years","Perfect forward secrecy, ensured by ephemeral key exchange that does not depend on the long-term key","Larger symmetric block sizes, which by themselves prevent decryption of any previously captured traffic"], correct:2, explanation:"Forward secrecy via ephemeral keys protects past sessions even if the long-term key leaks; authentication, longer validity, and block size do not provide this." },
  { id:71036, domain:3, level:2, question:"Which practice helps ensure that a compromised application cannot read another application's secrets on the same host?", options:["Storing all applications' secrets in one shared world-readable file for simplicity of deployment","Granting every application root privileges so secret access never causes permission errors at all as the architecture currently stands","Using one identical secret value across all applications so there is less to manage over time","Scoping each application's secret access to its own identity and isolating secrets between workloads"], correct:3, explanation:"Per-identity scoping and isolation prevent cross-application secret theft; shared readable files, universal root, and identical secrets enable it." },
  { id:71037, domain:3, level:3, question:"An engineer must verify that a downloaded software package is both authentic and unmodified. Which combination provides both assurances?", options:["A digital signature from the vendor over the package, verified against the vendor's trusted public key","A file size check against a number posted on an unauthenticated mirror site somewhere online","An MD5 hash retrieved from the same untrusted source that hosted the package download itself","A claim on the download page stating that the package is safe and has not been modified at all during day-to-day operations"], correct:0, explanation:"A vendor signature verified with a trusted public key proves authenticity and integrity; size checks, MD5 from untrusted sources, and webpage claims do not." },
  { id:71038, domain:3, level:2, question:"Which describes the correct handling of cryptographic keys at the end of their cryptoperiod?", options:["Continuing to use the key indefinitely because rotating it would require operational effort in the scenario being described","Retiring the key from active use and securely destroying or archiving it according to policy","Publishing the retired key so that auditors can independently verify past encrypted traffic","Reusing the retired key for a different unrelated system to extract more value from it"], correct:1, explanation:"Retiring and securely destroying or archiving keys per policy is correct; indefinite use, publishing keys, and reuse for other systems are insecure." },
  { id:71039, domain:3, level:3, question:"A system requires that even database administrators cannot read sensitive fields. Which engineering pattern achieves this?", options:["Relying on database role permissions alone, which administrators can change or bypass at will anyway over the lifetime of the system","Storing the data in plaintext but auditing administrator queries after the fact for misuse later","Application-layer encryption where plaintext is encrypted before storage and keys are kept outside the database","Encrypting the disk volume only, which still exposes plaintext to anyone with valid database access"], correct:2, explanation:"App-layer encryption with externally held keys hides plaintext from DBAs; role permissions, post-hoc auditing, and volume-only encryption still expose data to privileged DB access." },
  { id:71040, domain:3, level:2, question:"Which is the most appropriate use of a hardware security module in a payment processing environment?", options:["Acting as the main web server that renders the payment pages shown to customers in their browsers","Serving as the general-purpose file share where transaction receipts are archived for later retrieval in most real deployments","Functioning as the load balancer that distributes incoming payment requests across backend servers","Generating, storing, and using cryptographic keys for encryption and signing within tamper-resistant hardware"], correct:3, explanation:"An HSM securely generates, stores, and uses keys in tamper-resistant hardware; it is not a web server, file share, or load balancer." },
  { id:71041, domain:3, level:3, question:"An engineer must mitigate padding-oracle style attacks in an application's encryption. Which design choice is most robust?", options:["Using authenticated encryption so that any tampering is detected before decryption of the plaintext proceeds","Returning detailed decryption error messages so clients can troubleshoot malformed ciphertext quickly under typical operating conditions","Switching to a longer key with the same unauthenticated CBC mode used in the original design","Retrying decryption several times whenever a padding error occurs in case it was just transient"], correct:0, explanation:"Authenticated encryption (e.g., GCM or encrypt-then-MAC) detects tampering and eliminates padding oracles; detailed errors leak information, longer keys do not fix the mode, and retries help nothing." },
  { id:71042, domain:3, level:2, question:"Which best explains why key escrow can introduce security risk despite its recovery benefits?", options:["Escrow makes the original key mathematically weaker each time a recovery copy is generated from it","The escrowed copy of the key becomes an additional high-value target whose compromise exposes data","Escrow prevents the legitimate owner from ever being able to use their own key again afterward","Escrow automatically publishes the key to the public so that anyone can perform recovery at will"], correct:1, explanation:"An escrowed key copy is an extra target whose compromise exposes data; escrow does not weaken the math, lock out the owner, or publish keys publicly." },
  { id:71043, domain:3, level:3, question:"A design must ensure that compromise of a single signing key does not allow forging all historical and future releases. Which approach helps most?", options:["Using one master signing key forever so that verification logic only ever needs to trust one key","Storing the signing key in source control so that the whole team can audit how releases are signed for the foreseeable future","Using distinct keys per release line with key rotation and transparency logging of all signing events","Disabling signature verification on clients so a key compromise would have no real impact at all"], correct:2, explanation:"Distinct rotated keys with transparency logging contain a key compromise; one eternal key, source-control storage, and disabled verification make compromise catastrophic." },
  { id:71044, domain:4, level:3, question:"A CISO must quantify cyber risk for the board in financial terms. Which method expresses expected loss using probability and impact distributions?", options:["A red-amber-green heat map relying on subjective color assignments chosen for each system","A simple count of the total vulnerabilities discovered during the last quarterly network scan throughout the whole environment","The number of security awareness emails that were sent to staff during each calendar month","Factor Analysis of Information Risk producing annualized loss exposure expressed as financial ranges"], correct:3, explanation:"FAIR quantifies risk as probabilistic loss exposure for financial discussion; heat maps are qualitative, and vuln counts or email tallies are activity metrics, not risk." },
  { id:71045, domain:4, level:2, question:"An organization must justify cross-border transfers of EU personal data after an adequacy decision is invalidated. Which mechanism remains valid under GDPR?", options:["Standard Contractual Clauses supplemented by a documented transfer impact assessment of the destination","A verbal agreement reached informally between the two companies' respective marketing departments","Posting a privacy notice on the public website without including any binding contractual terms","Encrypting the data once while it is at rest with no contractual safeguards applied to the transfer in practice as well as in theory"], correct:0, explanation:"SCCs plus a transfer impact assessment provide a lawful GDPR transfer basis; verbal deals, a notice alone, or encryption without contractual safeguards are insufficient." },
  { id:71046, domain:4, level:3, question:"A company processing card data wants to minimize PCI DSS scope. Which decision most effectively reduces the cardholder data environment?", options:["Storing the full primary account number in every microservice to simplify reconciliation later on according to the proposed plan","Tokenizing primary account numbers at capture so downstream systems never store or process real card data","Logging the full primary account number in application logs to make production debugging easier","Granting all developers direct production database access in order to speed up support requests"], correct:1, explanation:"Tokenization removes real PANs from downstream systems, shrinking PCI scope; storing or logging PANs and broad prod access expand scope and risk." },
  { id:71047, domain:4, level:2, question:"During a third-party risk assessment a vendor refuses to share its SOC 2 report. Which alternative best provides assurance over the vendor's controls?", options:["Trusting the vendor's marketing claims that it is fully secure and already certified by everyone","Assuming the vendor is low risk simply because it is a large and well-known household brand name","A completed standardized security questionnaire backed by a contractual right-to-audit clause for verification","Skipping the assessment entirely because the project onboarding deadline is rapidly approaching now whenever the situation arises"], correct:2, explanation:"A standardized questionnaire with audit rights gives verifiable assurance; marketing claims, brand reputation, or skipping the assessment provide no real evidence." },
  { id:71048, domain:4, level:3, question:"A manufacturer must address supply-chain risk in purchased firmware. Which control most directly enables verification of component provenance?", options:["Asking the supplier to verbally confirm that the firmware is completely safe to deploy in production as the architecture currently stands","Running the firmware in production first and simply watching for any obvious failures to appear","Relying only on the supplier's company logo being printed on the outside of the shipping box","Requiring a signed software bill of materials with verifiable attestations for each included component"], correct:3, explanation:"A signed SBOM with attestations lets the buyer verify provenance and detect tampering; verbal assurance, production testing, and branding provide no provenance verification." },
  { id:71049, domain:4, level:1, question:"Which document type formally defines acceptable use, responsibilities, and consequences at the highest governance level?", options:["A security policy approved by leadership that states the organization's rules and responsibilities","A firewall rule set that specifies which network traffic is permitted or denied at the perimeter during day-to-day operations","A network diagram that depicts how the organization's systems are physically interconnected","A patch deployment log that records which updates were installed on each endpoint and when"], correct:0, explanation:"A security policy is the top-level governance statement of rules and responsibilities; firewall rules, diagrams, and logs are operational artifacts, not governance policy." },
  { id:71050, domain:4, level:2, question:"A risk committee faces a low-probability, catastrophic-impact scenario that is too costly to fully mitigate. Which treatment is most appropriate?", options:["Accept the risk silently without informing any of the executive stakeholders about its existence in the scenario being described","Transfer the residual risk through cyber insurance after first applying cost-effective baseline controls","Ignore the scenario entirely because its probability is currently assessed as being very low","Mitigate it fully no matter the cost, even if doing so would effectively bankrupt the business"], correct:1, explanation:"Transferring residual catastrophic risk via insurance after baseline controls is rational; silent acceptance, ignoring it, or bankrupting mitigation are poor governance choices." },
  { id:71051, domain:4, level:3, question:"An auditor maps controls to multiple frameworks to avoid duplicate work. Which approach best supports a unified compliance program?", options:["Maintaining entirely separate and unlinked control sets for each individual regulation in scope","Choosing only the single easiest framework to implement and ignoring all of the other requirements","Adopting a common control framework that cross-maps a single control set to NIST, ISO, and PCI requirements","Documenting controls only after each regulator has already issued a formal finding against the firm over the lifetime of the system"], correct:2, explanation:"A common control framework with cross-mappings satisfies overlapping requirements once; separate silos duplicate effort and selective or reactive approaches leave gaps." },
  { id:71052, domain:4, level:2, question:"A breach of EU personal data is confirmed Monday morning. Under GDPR, what is the controller's primary notification obligation to the supervisory authority?", options:["Wait until the full forensic investigation has been completely finished before notifying anyone in most real deployments","Notify only if the breach happens to appear in the news media coverage during that same week","Delay all notification until the next regularly scheduled quarterly compliance review meeting","Notify the supervisory authority without undue delay, generally within seventy-two hours of becoming aware"], correct:3, explanation:"GDPR requires notifying the supervisory authority within 72 hours of awareness; waiting for full investigation, media coverage, or a quarterly cycle violates the timeline." },
  { id:71053, domain:4, level:3, question:"A board asks how to measure whether security investments reduce risk over time. Which metric set demonstrates risk reduction rather than mere activity?", options:["Trends in residual risk exposure together with mean time to detect and respond across the security program","The total number of antivirus signatures that were downloaded by endpoints during the quarter","The count of security training slides that the awareness team produced over the past year","The number of firewall log lines that the perimeter devices generated on an average business day under typical operating conditions"], correct:0, explanation:"Residual risk trends and MTTD/MTTR show real risk reduction; signature counts, slide counts, and log volume are activity metrics, not outcomes." },
  { id:71054, domain:4, level:3, question:"An organization must demonstrate due diligence in selecting cloud providers for regulated workloads. Which evidence best supports this?", options:["A glossy vendor brochure listing impressive-sounding security features without any independent validation across the affected systems","Independent audit attestations such as SOC 2 or ISO 27001 reviewed against the organization's requirements","A single phone call to a sales representative who verbally assured the team that everything is secure","The provider's market share figures, on the assumption that popularity implies adequate security controls"], correct:1, explanation:"Independent attestations reviewed against requirements show due diligence; brochures, sales assurances, and market share are not evidence of control effectiveness." },
  { id:71055, domain:4, level:2, question:"Which best distinguishes a qualitative from a quantitative risk assessment?", options:["Qualitative always produces exact dollar figures, while quantitative only ever uses vague descriptive labels for the foreseeable future","Both approaches produce identical numeric outputs and differ only in the color used to display them","Qualitative uses ranked categories like high or low, while quantitative assigns numeric values such as monetary loss","Quantitative assessments are inherently less rigorous because numbers are easier to manipulate than words"], correct:2, explanation:"Qualitative ranks risk in categories; quantitative assigns numeric values like expected loss. The other options invert or mischaracterize the two methods." },
  { id:71056, domain:4, level:3, question:"A company must comply with overlapping requirements from PCI DSS and a regional privacy law. How should it reconcile potentially conflicting controls?", options:["Comply only with whichever regulation imposes the smaller financial penalty for noncompliance","Pick one regulation arbitrarily and document that the other was simply considered out of scope","Average the two requirements together to produce a single middle-of-the-road control level","Map both requirement sets and apply the most stringent control where they overlap or conflict"], correct:3, explanation:"Applying the most stringent control where requirements overlap satisfies both; choosing by penalty size, arbitrary selection, or averaging risks noncompliance." },
  { id:71057, domain:4, level:1, question:"Which is the primary purpose of a business impact analysis?", options:["Identifying critical processes and the impact of their disruption to prioritize recovery objectives","Listing every individual software vulnerability present across the organization's entire estate in practice as well as in theory","Documenting the marketing strategy the company will use to launch its next product line shortly","Recording the personal contact phone numbers of all employees for the office directory listing"], correct:0, explanation:"A BIA identifies critical processes and disruption impact to set recovery priorities; it is not a vulnerability list, marketing plan, or contact directory." },
  { id:71058, domain:4, level:3, question:"An organization wants to ensure its risk register drives action rather than sitting idle. Which practice is most effective?", options:["Recording every risk once at creation and never revisiting any of them again in the future","Assigning each risk an owner, treatment decision, and review date with progress tracked to closure","Listing risks without assigning any owners so that responsibility remains shared by everyone equally","Keeping the register confidential from the very leaders who must decide how to treat the risks"], correct:1, explanation:"Owners, treatment decisions, review dates, and tracked progress make a register actionable; one-time recording, ownerless entries, and hiding it from leaders render it inert." },
  { id:71059, domain:4, level:2, question:"Under a shared responsibility model for IaaS, which security task generally remains the customer's responsibility?", options:["Maintaining the physical security of the data centers where the cloud hardware is actually housed","Patching the underlying hypervisor software that the cloud provider operates beneath customer workloads whenever the situation arises","Securing the operating systems, applications, and data that the customer deploys onto the cloud infrastructure","Replacing failed physical disks and network cabling within the provider's facilities when they break"], correct:2, explanation:"In IaaS the customer secures their OS, apps, and data; the provider handles physical security, the hypervisor, and hardware maintenance." },
  { id:71060, domain:4, level:3, question:"A regulator requires evidence that access to sensitive data is appropriate and reviewed. Which control most directly satisfies this?", options:["A one-time access grant at hire that is never subsequently reviewed for the duration of employment as the architecture currently stands","An open policy allowing any employee to request and instantly receive access to any system at all","A spreadsheet of access listing only system names with no record of who actually holds the access","Periodic access recertification campaigns where data owners review and attest to each user's entitlements"], correct:3, explanation:"Periodic recertification with owner attestation evidences appropriate, reviewed access; one-time grants, open access, and incomplete spreadsheets do not." },
  { id:71061, domain:4, level:2, question:"Which best describes the role of a data protection impact assessment under GDPR?", options:["Evaluating and mitigating privacy risks before undertaking processing likely to result in high risk to individuals","Calculating the exact financial penalty the company will owe if it suffers a data breach later","Listing the marketing campaigns that will use the personal data once the processing is approved during day-to-day operations","Recording the brand of database software the organization chose to store the personal data in"], correct:0, explanation:"A DPIA assesses and mitigates privacy risk before high-risk processing; it is not a penalty calculator, marketing list, or software inventory." },
  { id:71062, domain:4, level:3, question:"A company outsources critical operations to a single supplier. Which governance control best addresses concentration risk?", options:["Trusting that the single supplier will never fail because it has been reliable so far historically","Defining exit strategies and alternative suppliers with contractual continuity and portability requirements","Signing the longest possible contract term so the relationship is locked in for many years ahead","Avoiding any documentation of dependencies so that competitors cannot learn the supplier's identity in the scenario being described"], correct:1, explanation:"Exit strategies, alternatives, and continuity/portability terms address concentration risk; blind trust, long lock-in, and hidden dependencies increase it." },
  { id:71063, domain:4, level:1, question:"Which statement correctly describes residual risk?", options:["The total risk that exists before any security controls of any kind have been implemented yet","The risk that has been completely eliminated and therefore no longer requires any monitoring","The risk that remains after controls have been applied to reduce the original inherent risk","The risk that applies only to third parties and never to the organization's own internal systems"], correct:2, explanation:"Residual risk is what remains after controls are applied; inherent risk is pre-control, and risk is rarely fully eliminated or limited only to third parties." },
  { id:71064, domain:4, level:3, question:"An organization must show auditors that security controls operate effectively over time, not just at a point in time. Which evidence best demonstrates this?", options:["A single screenshot of a control configuration captured on the morning of the audit visit only","A verbal assurance from the IT manager that the controls have always worked correctly throughout in most real deployments","A policy document describing the intended controls without any evidence that they actually ran","Continuous control monitoring with sampled evidence and exception tracking across the audit period"], correct:3, explanation:"Continuous monitoring with sampled evidence over the period shows operating effectiveness; a single screenshot, verbal assurance, or policy-only documentation do not." },
  { id:71065, domain:4, level:2, question:"Which framework is most directly intended to help organizations manage and reduce cybersecurity risk through functions like identify, protect, detect, respond, and recover?", options:["The NIST Cybersecurity Framework, which organizes cybersecurity outcomes into core functions","The accounting standard governing how revenue must be recognized in financial statements quarterly","A networking specification defining how Ethernet frames are formatted on a local network segment","A building code that dictates fire suppression requirements for commercial office construction work"], correct:0, explanation:"The NIST CSF organizes cybersecurity risk management into core functions; accounting standards, Ethernet specs, and building codes are unrelated to cyber risk." },
  { id:71066, domain:4, level:3, question:"A company must decide whether to accept, mitigate, transfer, or avoid a specific risk. Which factor should most influence the choice?", options:["The personal preference of whichever manager happens to be assigned the risk on a given day","The cost of treatment weighed against the potential impact and the organization's defined risk appetite","The alphabetical position of the risk's name within the organization's master risk register listing across the affected systems","The amount of budget left over at the end of the fiscal year after all other spending is done"], correct:1, explanation:"Treatment choice should weigh cost against impact within risk appetite; manager whim, alphabetical order, and leftover budget are not sound bases for risk decisions." },
  { id:71067, domain:4, level:1, question:"Which is a key reason organizations adopt a formal data classification scheme?", options:["To increase the total volume of data retained so that nothing is ever accidentally deleted at all for the foreseeable future","To ensure that every single piece of data receives exactly the same maximum level of protection","To apply protection and handling requirements proportionate to the sensitivity of each data category","To make all data publicly accessible so that classification labels become unnecessary over time"], correct:2, explanation:"Classification lets controls scale to sensitivity; it is not about retaining everything, treating all data identically, or making data public." },
  { id:71068, domain:4, level:3, question:"An organization must demonstrate accountability for personal data processing to regulators. Which practice most directly supports this principle?", options:["Processing personal data freely and only documenting anything after a regulator specifically asks for it","Deleting all processing records immediately so there is no paper trail for regulators to examine later","Assuming accountability is satisfied simply because the company has a privacy policy on its website","Maintaining records of processing activities, documented legal bases, and evidence of applied safeguards"], correct:3, explanation:"Records of processing, documented legal bases, and safeguard evidence demonstrate accountability; reactive, no-record, or policy-only approaches do not." },
  { id:71069, domain:4, level:1, question:"Which best describes the purpose of separation of duties as a governance control?", options:["Dividing critical tasks among multiple people so no single individual can complete a sensitive action alone","Ensuring that one trusted employee handles every step of a process for maximum efficiency gains","Assigning all administrative privileges to a single account so that accountability is very clear in practice as well as in theory","Allowing employees to approve their own expense and access requests to reduce processing delays"], correct:0, explanation:"Separation of duties splits critical tasks to prevent unilateral action and fraud; concentrating tasks, single-account admin, and self-approval defeat it." },
  { id:71070, domain:4, level:3, question:"A company adopts an ISO 27001 ISMS. Which element is essential to demonstrate ongoing management commitment and improvement?", options:["A one-time certification audit after which no further reviews or improvements are ever conducted according to the proposed plan","A documented management review and continual improvement cycle tied to measurable security objectives","A collection of security tools purchased without any governing policies or measurable objectives","An informal understanding among staff that security is important but with nothing written down"], correct:1, explanation:"ISO 27001 requires management review and continual improvement against objectives; one-time certification, tools without governance, and informal understanding do not satisfy it." },
  { id:71071, domain:4, level:2, question:"Which is the most appropriate purpose of a service level agreement in a vendor security context?", options:["Describing the vendor's internal company culture and the perks it offers to its own employees","Listing the personal hobbies of the account manager assigned to the customer relationship today whenever the situation arises","Defining measurable commitments such as availability, response times, and security obligations with remedies","Specifying the exact font and color scheme the vendor must use on its public marketing website"], correct:2, explanation:"An SLA defines measurable commitments and remedies, including security obligations; culture, hobbies, and branding are irrelevant to an SLA's security purpose." },
  { id:71072, domain:4, level:3, question:"An organization must ensure that critical IT services can recover within defined timeframes after a disaster. Which paired metrics formalize this requirement?", options:["Mean time between failures and mean time to repair for the office printers and copiers only","Cost per gigabyte of storage and the monthly cloud bill averaged over the previous fiscal year","The number of help desk tickets resolved each week and the average customer satisfaction score","Recovery time objective and recovery point objective derived from the business impact analysis"], correct:3, explanation:"RTO and RPO, derived from the BIA, formalize recovery timeframes and acceptable data loss; printer MTBF, storage cost, and ticket metrics do not define recovery objectives." },
  { id:71073, domain:4, level:2, question:"Which best explains why least privilege is a foundational governance principle?", options:["It limits the damage a compromised account or insider can cause by restricting access to what is needed","It guarantees that no account will ever be compromised because privileges are kept intentionally low during day-to-day operations","It removes the need for any monitoring since low-privilege accounts cannot cause any harm at all","It ensures that every user receives identical broad access to keep administration perfectly simple"], correct:0, explanation:"Least privilege limits the blast radius of compromise or insider misuse; it does not prevent all compromise, remove the need for monitoring, or grant uniform broad access." },
  { id:71074, domain:4, level:3, question:"A regulator asks how the organization ensures its incident response obligations are met across jurisdictions. Which approach best demonstrates compliance readiness?", options:["A single generic plan that ignores jurisdictional differences because they are too complicated to track","A jurisdiction-aware incident response plan mapping notification timelines and obligations to each applicable law","An assumption that one country's breach notification rules apply identically everywhere the firm operates in the scenario being described","A decision to notify no authorities at all unless a customer specifically complains about an incident"], correct:1, explanation:"A jurisdiction-aware plan mapping obligations to each law shows readiness; a generic plan, a one-size assumption, and refusing to notify create compliance gaps." },
  { id:71075, domain:4, level:1, question:"Which is the primary governance benefit of maintaining an accurate asset inventory?", options:["It primarily reduces the company's electricity bill by tracking which devices are powered on now","It exists mainly to satisfy the finance department's interest in depreciation schedules each year","It enables controls, patching, and risk decisions to be applied to all known assets without gaps","It serves chiefly as a marketing tool to show customers how much equipment the company owns"], correct:2, explanation:"An accurate inventory ensures controls and risk decisions cover all assets; energy savings, depreciation, and marketing are not its primary governance purpose." },
  { id:71076, domain:4, level:3, question:"A company must evaluate the risk of a newly discovered critical vulnerability in a widely deployed component. Which factor most appropriately drives remediation urgency?", options:["The alphabetical order of the affected software product's name as listed in the vendor catalog","The personal familiarity of the security team with the specific vendor that produced the component in most real deployments","The total number of unrelated patches that the organization happened to apply earlier that month","Exploitability, exposure of affected assets, and business impact combined into a risk-based prioritization"], correct:3, explanation:"Exploitability, exposure, and impact drive risk-based remediation urgency; product name order, team familiarity, and unrelated patch counts are irrelevant." },
  { id:71077, domain:4, level:1, question:"Which statement correctly describes the relationship between a threat, a vulnerability, and risk?", options:["Risk arises when a threat has the potential to exploit a vulnerability and cause adverse impact","A vulnerability and a threat are exactly the same thing described using two different words","Risk exists only when a threat is present even if there is no vulnerability for it to exploit at all","A vulnerability always guarantees a successful attack regardless of whether any threat exists"], correct:0, explanation:"Risk is the potential for a threat to exploit a vulnerability and cause impact; threats and vulnerabilities differ, and neither alone guarantees risk or a successful attack." },
  { id:71078, domain:4, level:3, question:"An organization wants assurance that its security program aligns with business objectives and is governed effectively. Which structure best provides this oversight?", options:["A single junior analyst informally tracking security tasks without any executive visibility at all","A security governance committee with executive sponsorship that reviews risk, strategy, and program metrics","An external auditor who reviews the program only once every several years with no interim oversight","A collection of unrelated team chat channels where security topics are occasionally mentioned briefly across the affected systems"], correct:1, explanation:"An executive-sponsored governance committee aligns security with business objectives; a lone analyst, infrequent audits, and ad hoc chats lack effective oversight." },
  { id:71079, domain:4, level:1, question:"Which best describes the purpose of a data retention policy?", options:["Ensuring that all data is kept forever so that nothing can ever be lost under any circumstances","Deleting all data immediately after creation to minimize the storage costs incurred by the company for the foreseeable future","Specifying how long different categories of data are kept and when they must be securely disposed of","Allowing each employee to individually decide how long to keep any data they personally handle"], correct:2, explanation:"A retention policy defines retention periods and secure disposal per data category; keeping everything, deleting immediately, and individual discretion are not sound policy." },
  { id:71080, domain:4, level:3, question:"A company must prove to customers that its controls are designed and operating effectively over a period. Which report type is most appropriate to request from a service provider?", options:["A one-page marketing summary that broadly claims the provider takes security very seriously indeed throughout the whole environment","A SOC 2 Type I report alone, which only attests to control design at a single point in time","An internal self-assessment with no independent auditor involvement of any kind whatsoever","A SOC 2 Type II report covering control design and operating effectiveness over a defined time period"], correct:3, explanation:"A SOC 2 Type II covers design and operating effectiveness over time; marketing summaries, Type I (point-in-time), and unaudited self-assessments provide weaker assurance." },
  { id:71081, domain:4, level:2, question:"Which is the most appropriate governance response when a critical control is found to have a recurring exception?", options:["Performing root-cause analysis and either remediating the control or formally accepting the documented risk","Removing the control entirely so that exceptions can no longer be recorded against it going forward","Ignoring the exceptions because the control has failed several times already without obvious harm","Hiding the exceptions from auditors so that the control continues to appear fully effective on paper in practice as well as in theory"], correct:0, explanation:"Root-cause analysis with remediation or formal risk acceptance is sound governance; removing the control, ignoring exceptions, and hiding them are improper." },
  { id:71082, domain:4, level:3, question:"An organization adopts a privacy-by-design approach for a new product. Which practice most directly embodies this principle?", options:["Collecting as much user data as possible first and deciding later what might be useful to keep","Embedding data minimization and default privacy protections into the design before development begins","Adding a privacy notice to the finished product just before launch without changing any design","Leaving all privacy decisions to the legal team to handle only after customer complaints arrive according to the proposed plan"], correct:1, explanation:"Privacy by design embeds minimization and protective defaults from the start; over-collection, late notices, and reactive legal handling contradict the principle." },
  { id:71083, domain:4, level:1, question:"Which best describes the purpose of a risk appetite statement?", options:["Listing every technical vulnerability the organization currently has across all of its systems","Recording the exact dollar amount spent on the security budget for the current fiscal year","Defining the amount and type of risk leadership is willing to accept in pursuit of objectives","Describing the specific brands of security products the organization has chosen to deploy"], correct:2, explanation:"A risk appetite statement defines acceptable risk in pursuit of objectives; it is not a vulnerability list, budget figure, or product catalog." },
  { id:71084, domain:4, level:3, question:"A company must ensure that mergers and acquisitions do not introduce unmanaged cyber risk. Which due-diligence practice is most important?", options:["Connecting the target's networks to the parent company immediately to accelerate the integration","Assuming the target's security is adequate because the acquisition deal was financially attractive as the architecture currently stands","Postponing any security review until well after the integration of all systems is fully complete","Assessing the target's security posture, breach history, and compliance gaps before integrating its systems"], correct:3, explanation:"Pre-integration assessment of posture, breach history, and compliance gaps manages M&A cyber risk; immediate connection, financial assumptions, and post-hoc review invite unmanaged risk." },
  { id:71085, domain:4, level:2, question:"Which describes the correct treatment of compensating controls in a compliance program?", options:["Implementing alternative controls that meet the intent and rigor of a requirement that cannot be met directly","Ignoring a requirement entirely whenever the prescribed control is inconvenient to implement now","Documenting that a requirement is met when in fact nothing has actually been put in place at all","Applying a weaker control and asserting it is equivalent without any analysis of the residual risk during day-to-day operations"], correct:0, explanation:"Compensating controls meet a requirement's intent and rigor when the direct control is infeasible; ignoring, falsely claiming, or under-protecting without analysis are improper." },
  { id:71086, domain:4, level:3, question:"An organization wants to ensure third-party software it builds upon does not introduce license or security obligations it cannot meet. Which practice addresses this?", options:["Adopting any open-source dependency that solves the immediate problem without reviewing its terms","Reviewing dependency licenses and vulnerabilities through software composition analysis before adoption","Assuming all open-source software is free of both licensing obligations and security vulnerabilities in the scenario being described","Removing all third-party dependencies and rewriting every component entirely from scratch in-house"], correct:1, explanation:"Software composition analysis reviews licenses and vulnerabilities before adoption; blind adoption, false assumptions, and rewriting everything are reckless or impractical." },
  { id:71087, domain:4, level:2, question:"Which is the primary governance purpose of conducting regular security awareness training?", options:["Satisfying a single checkbox once at hire so the topic never needs to be revisited afterward","Replacing all technical security controls because trained employees make those controls unnecessary","Reducing human-factor risk by improving employees' ability to recognize and respond to threats","Entertaining staff with engaging content regardless of whether it changes any security behaviors"], correct:2, explanation:"Awareness training reduces human-factor risk by improving threat recognition; it is not a one-time checkbox, a replacement for technical controls, or mere entertainment." },
  { id:71088, domain:4, level:3, question:"A regulated organization must show that privileged administrative actions are accountable and traceable. Which control set best provides this?", options:["A single shared administrator account used by the whole team so the work gets done efficiently","Standing administrative rights granted permanently to many staff with no logging of their actions","An honor system where administrators are simply trusted to only do what is appropriate at all times in most real deployments","Privileged access management with session recording, just-in-time elevation, and individual accountability"], correct:3, explanation:"PAM with session recording, JIT elevation, and individual accountability makes privileged actions traceable; shared accounts, unlogged standing rights, and honor systems do not." },
  { id:71089, domain:4, level:2, question:"Which statement best captures the governance value of mapping controls to a recognized framework?", options:["It provides a common language and structure for assessing coverage, gaps, and maturity consistently","It guarantees that the organization can never suffer any security incident once mapping is complete","It eliminates the need for any independent auditing because the framework validates itself entirely","It primarily serves to make compliance reports longer so they appear more thorough to executives"], correct:0, explanation:"Framework mapping gives a common structure to assess coverage, gaps, and maturity; it does not guarantee immunity, remove the need for audits, or merely pad reports." },
  { id:71090, domain:4, level:3, question:"A company must decide how to handle a low-likelihood risk whose mitigation would cost far more than any plausible loss. Which treatment is most defensible?", options:["Spending whatever it takes to eliminate the risk completely regardless of the disproportionate cost","Formally accepting the risk with documented rationale and sign-off from an accountable risk owner","Quietly transferring the risk to another department without informing anyone that it was moved at all","Pretending the risk does not exist so that it never appears in any report shown to leadership"], correct:1, explanation:"Documented, signed-off acceptance is defensible when mitigation cost vastly exceeds plausible loss; disproportionate spending, covert transfer, and denial are not sound governance." },
  { id:71091, domain:1, level:2, question:"Which architectural control best prevents a compromised edge device from pivoting deeper into a corporate network?", options:["Placing edge devices on the core management VLAN so administrators can reach them more conveniently","Allowing the edge devices unrestricted lateral access so that troubleshooting is faster for the team","Segmenting the edge into a restricted zone with default-deny egress and brokered access to internal services","Relying entirely on the edge device's built-in firewall with its default vendor configuration unchanged for the foreseeable future"], correct:2, explanation:"A restricted edge zone with default-deny egress and brokered access blocks pivoting; core-VLAN placement, lateral freedom, and default vendor configs enable it." },
  { id:71092, domain:1, level:3, question:"An architect must ensure that a cloud workload identity cannot be assumed from outside the intended environment. Which control is most effective?", options:["Granting the role a trust policy that allows any principal in any account to assume it freely","Embedding a static credential for the role inside the application image distributed to all hosts throughout the whole environment","Trusting that obscurity of the role's name alone will prevent it from being assumed by attackers","Conditioning role assumption on source attributes such as account, network, and workload identity assertions"], correct:3, explanation:"Conditioning assumption on account, network, and identity assertions restricts misuse; open trust policies, static credentials, and obscurity do not prevent unauthorized assumption." },
  { id:71093, domain:2, level:2, question:"Which practice most directly improves the quality of evidence collected during a cloud incident?", options:["Exporting immutable copies of relevant logs and snapshots to an isolated forensic account promptly","Leaving all evidence in the compromised account where the attacker still retains active access","Relying on the attacker not to delete the logs while the investigation slowly proceeds over weeks in practice as well as in theory","Capturing only screenshots of the console instead of exporting the underlying structured log data"], correct:0, explanation:"Exporting immutable logs and snapshots to an isolated forensic account preserves evidence; leaving it in the breached account, trusting the attacker, or screenshots-only risk loss." },
  { id:71094, domain:2, level:3, question:"A threat hunter wants to detect token theft where an attacker reuses a stolen session cookie. Which signal best supports detection?", options:["The total number of cookies stored in the user's browser at the time the session was created","Anomalous device, IP, and user-agent context on an existing session that diverges from the original sign-in","The font size the user configured in their browser settings during the original authentication","The brand of antivirus installed on the workstation where the session was first established earlier according to the proposed plan"], correct:1, explanation:"Divergent device/IP/user-agent context on a live session signals stolen-cookie reuse; cookie counts, font size, and AV brand carry no session-hijack signal." },
  { id:71095, domain:3, level:2, question:"Which approach best protects symmetric keys distributed to many edge devices that cannot host an HSM?", options:["Shipping the same shared symmetric key to every device so that key management remains very simple whenever the situation arises","Embedding the key in the device firmware in plaintext so it is always available at startup time","Provisioning unique per-device keys derived from a protected master key held only in central secure hardware","Printing the key on a label attached to each device so technicians can read it during maintenance"], correct:2, explanation:"Unique per-device keys derived from a centrally protected master limit blast radius; shared keys, plaintext firmware keys, and printed labels expose all devices if one leaks." },
  { id:71096, domain:3, level:3, question:"An engineer must ensure that revoked certificates are honored even when clients cache aggressively. Which combination is most robust?", options:["Ten-year certificates with revocation checking disabled to avoid the overhead of frequent renewals","A single long-lived certificate shared across services so revocation only ever affects one entry","Relying solely on clients to manually clear their caches whenever a certificate is revoked by an admin","Short-lived certificates with automated renewal so revocation latency is minimized by natural expiry"], correct:3, explanation:"Short-lived certs with automation bound revocation exposure by design; long-lived certs without revocation, shared certs, and manual cache clearing leave revoked certs trusted." },
  { id:71097, domain:3, level:2, question:"Which best explains why reusing a nonce with the same key in AES-GCM is dangerous?", options:["It can break confidentiality and allow forgery by exposing the keystream and authentication relationships","It makes the ciphertext slightly larger but otherwise has no impact on the security of the data","It only affects performance by slowing down the encryption without weakening the protection at all during day-to-day operations","It causes the algorithm to silently fall back to a weaker cipher that is easier to break instead"], correct:0, explanation:"Reusing a GCM nonce with the same key can expose keystream and enable forgery, breaking confidentiality and integrity; it is not merely a size, speed, or fallback issue." },
  { id:71098, domain:4, level:2, question:"Which practice best supports an organization's ability to demonstrate compliance during an unannounced regulatory audit?", options:["Creating all of the required documentation only in the days immediately following an audit request","Maintaining continuously updated evidence and control documentation rather than assembling it reactively","Storing evidence informally across personal email inboxes that auditors cannot readily access at all","Assuming verbal explanations during the audit will suffice in place of any documented control evidence in the scenario being described"], correct:1, explanation:"Continuously maintained evidence supports unannounced audits; last-minute creation, scattered personal storage, and verbal-only explanations leave the organization unprepared." },
  { id:71099, domain:4, level:3, question:"A company must manage risk from open-source components across hundreds of applications. Which governance practice scales best?", options:["Asking each team to informally remember which open-source libraries their own applications happen to use over the lifetime of the system","Banning all open-source software outright so there is no third-party code to track or govern at all","Maintaining an organization-wide software bill of materials with automated vulnerability and license monitoring","Reviewing dependencies manually once per year in a spreadsheet that is rarely updated afterward"], correct:2, explanation:"An org-wide SBOM with automated monitoring scales open-source risk management; informal memory, outright bans, and yearly manual reviews do not scale or stay current." },
  { id:71100, domain:4, level:3, question:"An organization must ensure that data subject access requests are handled within legal deadlines at scale. Which approach is most effective?", options:["Handling each request ad hoc whenever an employee happens to notice it sitting in an inbox somewhere","Ignoring requests until a regulator formally intervenes and compels the organization to respond at last in most real deployments","Responding to every request with a generic denial regardless of the requester's actual legal rights","A documented and partly automated DSAR workflow with tracking, identity verification, and deadline alerting"], correct:3, explanation:"A tracked, partly automated DSAR workflow meets deadlines at scale; ad hoc handling, ignoring requests, and blanket denials risk legal noncompliance." },
];
